import { Question } from '../../types';

// ============================================================================
// CRO (CHIEF RISK OFFICER) QUESTIONS
// ============================================================================

export const insCroProfessionalQuestions: Question[] = [
  // ERM Framework
  { id: 'ins-cro-pr-01', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-erm-framework', type: 'scenario', content: { es: 'Su aseguradora opera en cinco países de América Latina con diferentes marcos regulatorios de solvencia. El directorio le solicita diseñar un marco ERM (Enterprise Risk Management) unificado que cumpla simultáneamente con los requisitos locales de cada jurisdicción y con las mejores prácticas internacionales (COSO ERM, ISO 31000). Actualmente, cada filial gestiona riesgos de forma independiente con metodologías dispares.\nContexto: El grupo tiene USD 2,000M en primas consolidadas. La casa matriz está en un país que migra hacia un marco tipo Solvencia II. Dos filiales tuvieron hallazgos regulatorios por deficiencias en gestión de riesgos el año pasado.', en: 'Your insurer operates in five Latin American countries with different solvency regulatory frameworks. The board asks you to design a unified ERM (Enterprise Risk Management) framework that simultaneously complies with local requirements in each jurisdiction and international best practices (COSO ERM, ISO 31000). Currently, each subsidiary manages risks independently with disparate methodologies.\nContext: The group has USD 2,000M in consolidated premiums. The parent company is in a country migrating toward a Solvency II-type framework. Two subsidiaries had regulatory findings for risk management deficiencies last year.', fr: 'Votre assureur opère dans cinq pays d\'Amérique latine avec différents cadres réglementaires de solvabilité. Le conseil vous demande de concevoir un cadre ERM unifié conforme aux exigences locales et aux meilleures pratiques internationales (COSO ERM, ISO 31000).\nContexte : Le groupe a 2 000 M USD en primes consolidées. La maison mère migre vers un cadre type Solvabilité II. Deux filiales ont eu des observations réglementaires l\'an dernier.' }, rubric: { es: 'Evaluar: (1) Diseño de taxonomía de riesgos unificada con flexibilidad local, (2) Gobernanza de riesgos (comités, líneas de reporte, roles y responsabilidades), (3) Metodología de identificación, medición y monitoreo de riesgos, (4) Apetito y tolerancia al riesgo a nivel grupo y filial, (5) Integración con planificación estratégica y presupuestación de capital, (6) Plan de remediación para las filiales con hallazgos regulatorios.', en: 'Evaluate: (1) Unified risk taxonomy design with local flexibility, (2) Risk governance (committees, reporting lines, roles and responsibilities), (3) Risk identification, measurement, and monitoring methodology, (4) Risk appetite and tolerance at group and subsidiary levels, (5) Integration with strategic planning and capital budgeting, (6) Remediation plan for subsidiaries with regulatory findings.', fr: 'Évaluer : (1) Taxonomie de risques unifiée avec flexibilité locale, (2) Gouvernance des risques, (3) Méthodologie d\'identification et mesure des risques, (4) Appétit et tolérance au risque, (5) Intégration avec la planification stratégique, (6) Plan de remédiation pour les filiales avec observations.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Solvency & Capital Adequacy
  { id: 'ins-cro-pr-02', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-solvency-capital', type: 'multiple-choice', content: { es: 'El ratio de solvencia regulatorio de su aseguradora cayó del 185% al 145% en un trimestre debido a la combinación de un terremoto severo y una caída del 18% en los mercados de renta variable. El mínimo regulatorio es 120% y el apetito de riesgo interno es 160%. ¿Cuál es su plan de acción inmediato como CRO?', en: 'Your insurer\'s regulatory solvency ratio dropped from 185% to 145% in one quarter due to a severe earthquake combined with an 18% equity market decline. The regulatory minimum is 120% and your internal risk appetite is 160%. What is your immediate action plan as CRO?', fr: 'Le ratio de solvabilité de votre assureur est passé de 185% à 145% en un trimestre suite à un tremblement de terre et une chute de 18% des marchés actions. Le minimum réglementaire est de 120% et l\'appétit de risque interne de 160%. Quel est votre plan d\'action immédiat ?' }, options: [{ id: 'a', text: { es: 'Activar el plan de contingencia de capital: ejecutar la revisión de límites de retención, activar la línea de reaseguro facultativo catastrófico pre-negociada, reducir exposición en renta variable, convocar sesión extraordinaria del comité de riesgos para recalibrar el apetito de riesgo y preparar la comunicación proactiva al regulador', en: 'Activate the capital contingency plan: execute retention limit review, activate the pre-negotiated catastrophe facultative reinsurance line, reduce equity exposure, convene an extraordinary risk committee session to recalibrate risk appetite, and prepare proactive communication to the regulator', fr: 'Activer le plan de contingence du capital : réviser les limites de rétention, activer la ligne de réassurance facultative catastrophe pré-négociée, réduire l\'exposition aux actions, convoquer une session extraordinaire du comité des risques et préparer la communication proactive au régulateur' }, value: 100 }, { id: 'b', text: { es: 'Esperar al próximo trimestre para ver si los mercados se recuperan y el ratio mejora naturalmente', en: 'Wait until next quarter to see if markets recover and the ratio improves naturally', fr: 'Attendre le prochain trimestre pour voir si les marchés se rétablissent' }, value: 10 }, { id: 'c', text: { es: 'Solicitar inmediatamente una inyección de capital a los accionistas', en: 'Immediately request a capital injection from shareholders', fr: 'Demander immédiatement une injection de capital aux actionnaires' }, value: 25 }, { id: 'd', text: { es: 'Reclasificar activos de inversión para obtener un tratamiento de capital más favorable en el cálculo regulatorio', en: 'Reclassify investment assets to obtain a more favorable capital treatment in the regulatory calculation', fr: 'Reclasser les actifs d\'investissement pour obtenir un traitement de capital plus favorable' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Catastrophe Modeling
  { id: 'ins-cro-pr-03', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-catastrophe-modeling', type: 'scenario', content: { es: 'Su aseguradora tiene una cartera de seguros patrimoniales concentrada en zonas sísmicas y costeras del Caribe y Centroamérica (USD 800M en suma asegurada). Los modelos catastróficos actuales (AIR, RMS) muestran un PML (Probable Maximum Loss) a 1-en-250 años de USD 120M, pero los eventos recientes sugieren que los modelos pueden estar subestimando el riesgo por efectos del cambio climático.\nContexto: El programa de reaseguro actual cubre hasta USD 100M por evento. El costo del reaseguro catastrófico aumentó 35% en la última renovación. El regulador está exigiendo pruebas de estrés climáticas.', en: 'Your insurer has a property insurance portfolio concentrated in seismic and coastal zones of the Caribbean and Central America (USD 800M total insured value). Current catastrophe models (AIR, RMS) show a PML (Probable Maximum Loss) at 1-in-250 years of USD 120M, but recent events suggest models may be underestimating risk due to climate change effects.\nContext: The current reinsurance program covers up to USD 100M per event. Catastrophe reinsurance costs increased 35% at the last renewal. The regulator is requiring climate stress tests.', fr: 'Votre assureur a un portefeuille d\'assurance de biens concentré dans les zones sismiques et côtières des Caraïbes (800 M USD en somme assurée). Les modèles catastrophiques actuels montrent un PML à 1/250 ans de 120 M USD, mais les événements récents suggèrent une sous-estimation due au changement climatique.\nContexte : Le programme de réassurance couvre jusqu\'à 100 M USD par événement. Le coût a augmenté de 35% au dernier renouvellement.' }, rubric: { es: 'Evaluar: (1) Análisis crítico de las limitaciones de los modelos catastróficos actuales, (2) Propuesta de ajustes al modelo (climate-conditioned cat models, cargos por tendencia climática), (3) Estrategia de optimización del programa de reaseguro (estructura, capas, ILS/cat bonds), (4) Medidas de mitigación del riesgo de concentración geográfica, (5) Marco de pruebas de estrés climáticas para el regulador, (6) Análisis costo-beneficio de retención vs. transferencia de riesgo.', en: 'Evaluate: (1) Critical analysis of current catastrophe model limitations, (2) Proposed model adjustments (climate-conditioned cat models, climate trend loads), (3) Reinsurance program optimization strategy (structure, layers, ILS/cat bonds), (4) Geographic concentration risk mitigation measures, (5) Climate stress testing framework for the regulator, (6) Cost-benefit analysis of retention vs. risk transfer.', fr: 'Évaluer : (1) Analyse critique des modèles catastrophiques, (2) Ajustements proposés, (3) Optimisation du programme de réassurance, (4) Atténuation du risque de concentration, (5) Cadre de tests de stress climatiques, (6) Analyse coût-bénéfice rétention vs. transfert.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Operational Risk
  { id: 'ins-cro-pr-04', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-operational-risk', type: 'multiple-choice', content: { es: 'Un análisis de incidentes operacionales revela que el 40% de las pérdidas operativas de su aseguradora en los últimos tres años provienen de fraude interno y errores en el proceso de suscripción. El monto acumulado supera USD 15 millones. ¿Cuál es su enfoque integral para abordar esta situación?', en: 'An operational incident analysis reveals that 40% of your insurer\'s operational losses over the past three years come from internal fraud and underwriting process errors. The cumulative amount exceeds USD 15 million. What is your comprehensive approach to address this situation?', fr: 'Une analyse des incidents opérationnels révèle que 40% des pertes opérationnelles proviennent de fraudes internes et d\'erreurs de souscription. Le montant cumulé dépasse 15 millions USD. Quelle est votre approche globale ?' }, options: [{ id: 'a', text: { es: 'Implementar un programa integral: mapeo de procesos críticos con RCSA (Risk and Control Self-Assessment), fortalecimiento de controles automatizados en suscripción, sistema de detección de fraude con analítica avanzada, cultura de riesgo con línea de denuncia anónima, y establecimiento de KRIs con umbrales de escalamiento', en: 'Implement a comprehensive program: critical process mapping with RCSA (Risk and Control Self-Assessment), strengthened automated underwriting controls, fraud detection system with advanced analytics, risk culture with anonymous whistleblower hotline, and KRIs with escalation thresholds', fr: 'Mettre en œuvre un programme complet : cartographie RCSA des processus critiques, contrôles automatisés renforcés en souscription, système de détection de fraude avec analytique avancée, culture du risque avec ligne de dénonciation anonyme, et KRIs avec seuils d\'escalade' }, value: 100 }, { id: 'b', text: { es: 'Contratar una firma de auditoría externa para que investigue los casos de fraude y recomiende mejoras', en: 'Hire an external audit firm to investigate fraud cases and recommend improvements', fr: 'Engager un cabinet d\'audit externe pour enquêter et recommander des améliorations' }, value: 35 }, { id: 'c', text: { es: 'Reforzar las sanciones disciplinarias y comunicar tolerancia cero al fraude', en: 'Strengthen disciplinary sanctions and communicate zero tolerance for fraud', fr: 'Renforcer les sanctions disciplinaires et communiquer la tolérance zéro à la fraude' }, value: 25 }, { id: 'd', text: { es: 'Centralizar toda la suscripción en la casa matriz para mayor control', en: 'Centralize all underwriting at headquarters for greater control', fr: 'Centraliser toute la souscription au siège pour un meilleur contrôle' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Investment Risk
  { id: 'ins-cro-pr-05', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-investment-risk', type: 'open-text', content: { es: 'El portafolio de inversiones de su aseguradora (USD 1,200M) muestra los siguientes riesgos identificados: duración promedio de 4.2 años vs. duración de pasivos de 6.8 años, concentración del 25% en bonos soberanos de un país con perspectiva crediticia negativa, y exposición del 12% a fondos de inversión inmobiliarios con liquidez limitada. Como CRO, elabore un informe ejecutivo con su evaluación integral de los riesgos del portafolio y las recomendaciones prioritarias.', en: 'Your insurer\'s investment portfolio (USD 1,200M) shows the following identified risks: average duration of 4.2 years vs. liability duration of 6.8 years, 25% concentration in sovereign bonds from a country with a negative credit outlook, and 12% exposure to real estate investment funds with limited liquidity. As CRO, prepare an executive report with your comprehensive portfolio risk assessment and priority recommendations.', fr: 'Le portefeuille d\'investissements de votre assureur (1 200 M USD) présente les risques suivants : duration moyenne de 4,2 ans vs. 6,8 ans pour les passifs, concentration de 25% en obligations souveraines d\'un pays à perspective négative, et 12% d\'exposition à des fonds immobiliers peu liquides. En tant que CRO, préparez un rapport exécutif avec votre évaluation et recommandations.' }, rubric: { es: 'Evaluar: (1) Análisis del descalce de duración (gap de duración, impacto en solvencia ante movimientos de tasas), (2) Evaluación del riesgo de concentración soberana con escenarios de downgrade, (3) Análisis de riesgo de liquidez del portafolio inmobiliario, (4) Propuestas de rebalanceo con horizonte temporal, (5) Marco de límites de inversión integrado con el apetito de riesgo, (6) Métricas de seguimiento (VaR, stress tests, tracking error).', en: 'Evaluate: (1) Duration mismatch analysis (duration gap, solvency impact from rate movements), (2) Sovereign concentration risk assessment with downgrade scenarios, (3) Liquidity risk analysis of the real estate portfolio, (4) Rebalancing proposals with time horizon, (5) Investment limit framework integrated with risk appetite, (6) Monitoring metrics (VaR, stress tests, tracking error).', fr: 'Évaluer : (1) Analyse du décalage de duration, (2) Risque de concentration souveraine avec scénarios de dégradation, (3) Analyse du risque de liquidité immobilier, (4) Propositions de rééquilibrage, (5) Cadre de limites d\'investissement, (6) Métriques de suivi (VaR, stress tests).' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Regulatory Risk
  { id: 'ins-cro-pr-06', profileId: 'insurance-cro', categoryId: 'ins-cro-professional', competencyId: 'ins-cro-regulatory-risk', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene gestionando la relación con reguladores de seguros (superintendencias, comisiones de seguros) y liderando procesos de cumplimiento regulatorio como ORSA (Own Risk and Solvency Assessment), pruebas de estrés mandatorias y reportes de capital?', en: 'What level of experience do you have managing relationships with insurance regulators (superintendencies, insurance commissions) and leading regulatory compliance processes such as ORSA (Own Risk and Solvency Assessment), mandatory stress tests, and capital reporting?', fr: 'Quel niveau d\'expérience avez-vous dans la gestion des relations avec les régulateurs d\'assurance et la conduite de processus de conformité réglementaire tels que l\'ORSA, les tests de stress obligatoires et les rapports de capital ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en cumplimiento regulatorio', en: 'Limited regulatory compliance experience', fr: 'Expérience limitée en conformité réglementaire' }, max: { es: 'Amplia experiencia liderando ORSA, inspecciones regulatorias y diseño de marcos de cumplimiento en múltiples jurisdicciones', en: 'Extensive experience leading ORSA, regulatory inspections, and designing compliance frameworks across multiple jurisdictions', fr: 'Vaste expérience dans la direction de l\'ORSA, des inspections réglementaires et la conception de cadres de conformité multi-juridictions' } }, maxScore: 100, aiEvaluated: false, order: 6, isActive: true },
];

export const insCroSoftSkillsQuestions: Question[] = [
  // Risk Culture
  { id: 'ins-cro-ss-01', profileId: 'insurance-cro', categoryId: 'ins-cro-soft-skills', competencyId: 'ins-cro-risk-culture', type: 'scenario', content: { es: 'Una auditoría interna revela que los gerentes comerciales de su aseguradora han estado aprobando pólizas fuera de los lineamientos de suscripción establecidos para cumplir con metas de ventas trimestrales. El 15% de la producción del último trimestre presenta desviaciones significativas respecto a las normas de suscripción. El VP Comercial argumenta que las metas son demasiado agresivas y que sin flexibilidad no se pueden alcanzar.\nContexto: La siniestralidad en las pólizas con desviaciones es 25% superior al promedio de la cartera. El CEO ha estado presionando por crecimiento.', en: 'An internal audit reveals that your insurer\'s commercial managers have been approving policies outside established underwriting guidelines to meet quarterly sales targets. 15% of last quarter\'s production shows significant deviations from underwriting standards. The VP of Sales argues that targets are too aggressive and cannot be met without flexibility.\nContext: Claims ratio on deviated policies is 25% above the portfolio average. The CEO has been pushing for growth.', fr: 'Un audit interne révèle que les responsables commerciaux ont approuvé des polices hors des directives de souscription pour atteindre les objectifs de vente. 15% de la production du dernier trimestre présente des écarts significatifs.\nContexte : La sinistralité des polices déviantes est 25% supérieure à la moyenne. Le PDG pousse pour la croissance.' }, rubric: { es: 'Evaluar: (1) Equilibrio entre gestión de riesgo y viabilidad comercial, (2) Propuesta de marco de autoridad de suscripción con escalamientos claros, (3) Enfoque de comunicación con el CEO y VP Comercial sin antagonismo, (4) Plan de fortalecimiento de la cultura de riesgo (capacitación, incentivos alineados, three lines of defense), (5) Análisis cuantitativo del impacto financiero de las desviaciones, (6) Mecanismos de monitoreo continuo para detectar desviaciones futuras.', en: 'Evaluate: (1) Balance between risk management and commercial viability, (2) Proposed underwriting authority framework with clear escalations, (3) Communication approach with CEO and VP Sales without antagonism, (4) Risk culture strengthening plan (training, aligned incentives, three lines of defense), (5) Quantitative analysis of the financial impact of deviations, (6) Continuous monitoring mechanisms to detect future deviations.', fr: 'Évaluer : (1) Équilibre entre gestion des risques et viabilité commerciale, (2) Cadre d\'autorité de souscription, (3) Communication avec la direction, (4) Plan de renforcement de la culture du risque, (5) Analyse quantitative de l\'impact, (6) Mécanismes de surveillance continue.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Board Reporting
  { id: 'ins-cro-ss-02', profileId: 'insurance-cro', categoryId: 'ins-cro-soft-skills', competencyId: 'ins-cro-board-reporting', type: 'multiple-choice', content: { es: 'El presidente de la junta directiva le solicita rediseñar el informe de riesgos para el directorio. Actualmente es un documento de 60 páginas altamente técnico que los miembros no financieros del directorio no comprenden. ¿Cuál es su enfoque?', en: 'The board chair asks you to redesign the risk report for the board. Currently it is a 60-page highly technical document that non-financial board members do not understand. What is your approach?', fr: 'Le président du conseil vous demande de refondre le rapport de risques pour le conseil d\'administration. Actuellement c\'est un document de 60 pages hautement technique. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Diseñar un dashboard de riesgos ejecutivo con heat maps, indicadores de apetito de riesgo con semáforos, tendencias de los Top 10 riesgos, y secciones de deep-dive rotativas por categoría de riesgo, complementado con un anexo técnico bajo demanda y sesiones educativas trimestrales para el directorio', en: 'Design an executive risk dashboard with heat maps, risk appetite indicators with traffic lights, Top 10 risk trends, and rotating deep-dive sections by risk category, complemented by a technical appendix on demand and quarterly educational sessions for the board', fr: 'Concevoir un tableau de bord exécutif avec des heat maps, des indicateurs d\'appétit de risque, des tendances des 10 principaux risques et des sections approfondies rotatives, complété par des sessions éducatives trimestrielles' }, value: 100 }, { id: 'b', text: { es: 'Reducir el informe a 5 páginas con solo los indicadores regulatorios mínimos', en: 'Reduce the report to 5 pages with only the minimum regulatory indicators', fr: 'Réduire le rapport à 5 pages avec uniquement les indicateurs réglementaires minimaux' }, value: 25 }, { id: 'c', text: { es: 'Mantener el informe técnico completo y agregar un glosario de términos', en: 'Keep the full technical report and add a glossary of terms', fr: 'Garder le rapport technique complet et ajouter un glossaire' }, value: 10 }, { id: 'd', text: { es: 'Solicitar que se incorporen al directorio miembros con formación en gestión de riesgos', en: 'Request that board members with risk management backgrounds be added to the board', fr: 'Demander l\'ajout de membres du conseil ayant une formation en gestion des risques' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Cross-Functional Collaboration
  { id: 'ins-cro-ss-03', profileId: 'insurance-cro', categoryId: 'ins-cro-soft-skills', competencyId: 'ins-cro-cross-functional', type: 'open-text', content: { es: 'Como CRO, usted debe trabajar transversalmente con todas las áreas de la aseguradora: actuaría, suscripción, comercial, inversiones, tecnología y operaciones. Describa cómo construiría y mantendría relaciones de trabajo efectivas con cada una de estas áreas, asegurando que la gestión de riesgos sea vista como un socio estratégico y no como un obstáculo burocrático.', en: 'As CRO, you must work cross-functionally with all areas of the insurer: actuarial, underwriting, commercial, investments, technology, and operations. Describe how you would build and maintain effective working relationships with each of these areas, ensuring risk management is seen as a strategic partner rather than a bureaucratic obstacle.', fr: 'En tant que CRO, vous devez travailler transversalement avec toutes les directions de l\'assureur. Décrivez comment vous construiriez des relations de travail efficaces avec chaque direction, en vous assurant que la gestion des risques soit perçue comme un partenaire stratégique.' }, rubric: { es: 'Evaluar: (1) Estrategia diferenciada para cada área funcional, (2) Mecanismos de integración del riesgo en los procesos de negocio (embedded risk), (3) Equilibrio entre la función de control independiente y la colaboración, (4) Uso de comités multifuncionales y puntos de contacto regulares, (5) Comunicación de valor agregado de la gestión de riesgos con ejemplos concretos, (6) Manejo de conflictos de interés entre áreas.', en: 'Evaluate: (1) Differentiated strategy for each functional area, (2) Mechanisms for embedding risk into business processes, (3) Balance between independent control function and collaboration, (4) Use of cross-functional committees and regular touchpoints, (5) Communication of risk management value-add with concrete examples, (6) Managing inter-area conflicts of interest.', fr: 'Évaluer : (1) Stratégie différenciée pour chaque direction, (2) Intégration du risque dans les processus métier, (3) Équilibre entre contrôle indépendant et collaboration, (4) Comités transversaux, (5) Communication de la valeur ajoutée, (6) Gestion des conflits d\'intérêts.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Crisis Leadership
  { id: 'ins-cro-ss-04', profileId: 'insurance-cro', categoryId: 'ins-cro-soft-skills', competencyId: 'ins-cro-crisis-leadership', type: 'scale', content: { es: '¿Qué tan preparado se siente para liderar la respuesta de la organización ante una crisis mayor (evento catastrófico, ciberataque masivo, fraude significativo, pandemia) que amenace la continuidad del negocio y la solvencia de la aseguradora?', en: 'How prepared do you feel to lead the organization\'s response to a major crisis (catastrophic event, massive cyberattack, significant fraud, pandemic) that threatens business continuity and the insurer\'s solvency?', fr: 'Dans quelle mesure vous sentez-vous préparé pour diriger la réponse de l\'organisation face à une crise majeure (événement catastrophique, cyberattaque massive, fraude significative, pandémie) menaçant la continuité et la solvabilité de l\'assureur ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Poca experiencia en gestión de crisis', en: 'Little crisis management experience', fr: 'Peu d\'expérience en gestion de crise' }, max: { es: 'He liderado exitosamente la respuesta a múltiples crisis con impacto significativo', en: 'I have successfully led the response to multiple crises with significant impact', fr: 'J\'ai dirigé avec succès la réponse à de multiples crises d\'impact significatif' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

export const insCroReadinessQuestions: Question[] = [
  // Emerging Risks (Cyber, Climate, Pandemic)
  { id: 'ins-cro-rd-01', profileId: 'insurance-cro', categoryId: 'ins-cro-readiness', competencyId: 'ins-cro-emerging-risks', type: 'scenario', content: { es: 'Su aseguradora ha comenzado a suscribir seguros cibernéticos (cyber insurance) hace dos años con un portafolio creciente de USD 30M en primas. Un ataque de ransomware a un cliente corporativo importante ha generado un siniestro de USD 8M, el mayor de la cartera. Simultáneamente, los reaseguradores están endureciendo los términos y un estudio reciente indica que los modelos actuariales de riesgo cibernético tienen un margen de error del 40-60%.\nContexto: El CEO quiere triplicar la cartera de cyber en 3 años. Su equipo actuarial tiene experiencia limitada en modelado de riesgo cibernético. No existe regulación específica de cyber insurance en su jurisdicción.', en: 'Your insurer started underwriting cyber insurance two years ago with a growing portfolio of USD 30M in premiums. A ransomware attack on a major corporate client generated an USD 8M claim, the largest in the portfolio. Simultaneously, reinsurers are tightening terms and a recent study indicates cyber risk actuarial models have a 40-60% margin of error.\nContext: The CEO wants to triple the cyber portfolio in 3 years. Your actuarial team has limited cyber risk modeling experience. There is no specific cyber insurance regulation in your jurisdiction.', fr: 'Votre assureur souscrit des assurances cyber depuis deux ans avec un portefeuille croissant de 30 M USD en primes. Une attaque par rançongiciel a généré un sinistre de 8 M USD. Les réassureurs durcissent leurs conditions et les modèles actuariels ont une marge d\'erreur de 40-60%.\nContexte : Le PDG veut tripler le portefeuille en 3 ans. Votre équipe actuarielle a une expérience limitée en modélisation cyber.' }, rubric: { es: 'Evaluar: (1) Evaluación realista de la capacidad de la organización para suscribir riesgo cibernético, (2) Propuesta de límites de acumulación y concentración de riesgo cibernético, (3) Estrategia de mejora del modelado (datos, herramientas, talento especializado), (4) Enfoque de reaseguro para riesgo cibernético, (5) Recomendación al CEO con análisis riesgo-rendimiento, (6) Marco de suscripción con criterios de selección de riesgo cibernético.', en: 'Evaluate: (1) Realistic assessment of the organization\'s capability to underwrite cyber risk, (2) Proposed accumulation and concentration limits for cyber risk, (3) Modeling improvement strategy (data, tools, specialized talent), (4) Reinsurance approach for cyber risk, (5) CEO recommendation with risk-return analysis, (6) Underwriting framework with cyber risk selection criteria.', fr: 'Évaluer : (1) Évaluation réaliste des capacités de souscription cyber, (2) Limites d\'accumulation et concentration, (3) Stratégie d\'amélioration de la modélisation, (4) Approche de réassurance, (5) Recommandation au PDG avec analyse risque-rendement, (6) Cadre de souscription avec critères de sélection.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Risk Analytics & AI
  { id: 'ins-cro-rd-02', profileId: 'insurance-cro', categoryId: 'ins-cro-readiness', competencyId: 'ins-cro-risk-analytics', type: 'multiple-choice', content: { es: 'Su equipo de riesgos propone implementar modelos de machine learning para la detección temprana de deterioro en la siniestralidad y para predicción de escenarios de insolvencia. Los modelos han mostrado resultados prometedores en el backtesting pero presentan el problema de "caja negra" que dificulta su explicabilidad ante el regulador. ¿Cuál es su posición?', en: 'Your risk team proposes implementing machine learning models for early detection of claims deterioration and insolvency scenario prediction. The models show promising backtesting results but present a "black box" problem that makes them difficult to explain to the regulator. What is your position?', fr: 'Votre équipe de risques propose d\'implémenter des modèles de machine learning pour la détection précoce de la détérioration de la sinistralité. Les modèles montrent des résultats prometteurs mais posent le problème de la "boîte noire" face au régulateur. Quelle est votre position ?' }, options: [{ id: 'a', text: { es: 'Adoptar un enfoque híbrido: utilizar los modelos ML como herramienta complementaria de alerta temprana, mantener los modelos actuariales tradicionales como base del reporte regulatorio, invertir en técnicas de IA explicable (SHAP, LIME), y establecer un comité de validación de modelos con gobernanza clara', en: 'Adopt a hybrid approach: use ML models as complementary early warning tools, maintain traditional actuarial models as the basis for regulatory reporting, invest in explainable AI techniques (SHAP, LIME), and establish a model validation committee with clear governance', fr: 'Adopter une approche hybride : utiliser les modèles ML comme outils complémentaires d\'alerte précoce, maintenir les modèles actuariels traditionnels pour le réglementaire, investir dans l\'IA explicable (SHAP, LIME) et établir un comité de validation des modèles' }, value: 100 }, { id: 'b', text: { es: 'Rechazar los modelos ML hasta que el regulador emita directrices claras sobre su uso', en: 'Reject ML models until the regulator issues clear guidelines on their use', fr: 'Rejeter les modèles ML jusqu\'à ce que le régulateur émette des directives claires' }, value: 25 }, { id: 'c', text: { es: 'Implementar los modelos ML completamente y reemplazar los modelos actuariales tradicionales', en: 'Fully implement ML models and replace traditional actuarial models', fr: 'Implémenter complètement les modèles ML et remplacer les modèles actuariels traditionnels' }, value: 10 }, { id: 'd', text: { es: 'Delegar la decisión al equipo actuarial y de tecnología', en: 'Delegate the decision to the actuarial and technology teams', fr: 'Déléguer la décision aux équipes actuarielle et technologique' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Scenario Planning
  { id: 'ins-cro-rd-03', profileId: 'insurance-cro', categoryId: 'ins-cro-readiness', competencyId: 'ins-cro-scenario-planning', type: 'open-text', content: { es: 'El directorio le solicita desarrollar un ejercicio integral de planificación de escenarios para los próximos 5 años que considere los principales riesgos emergentes para la industria aseguradora en América Latina. Describa los escenarios que construiría, las variables clave, la metodología y cómo traduciría los resultados en acciones estratégicas concretas.', en: 'The board asks you to develop a comprehensive scenario planning exercise for the next 5 years considering the main emerging risks for the insurance industry in Latin America. Describe the scenarios you would construct, the key variables, the methodology, and how you would translate results into concrete strategic actions.', fr: 'Le conseil vous demande de développer un exercice complet de planification de scénarios à 5 ans pour les principaux risques émergents de l\'industrie de l\'assurance en Amérique latine. Décrivez les scénarios, les variables clés, la méthodologie et comment vous traduiriez les résultats en actions stratégiques concrètes.' }, rubric: { es: 'Evaluar: (1) Identificación de riesgos emergentes clave (cambio climático, digitalización, geopolítica, pandemias, regulación), (2) Construcción de escenarios plausibles y diferenciados (no solo optimista/pesimista), (3) Metodología rigurosa (drivers, interrelaciones, probabilidades), (4) Impacto cuantificado en métricas financieras y de solvencia, (5) Acciones estratégicas de mitigación y oportunidad por escenario, (6) Proceso de actualización y revisión periódica.', en: 'Evaluate: (1) Identification of key emerging risks (climate change, digitalization, geopolitics, pandemics, regulation), (2) Construction of plausible and differentiated scenarios, (3) Rigorous methodology (drivers, interrelationships, probabilities), (4) Quantified impact on financial and solvency metrics, (5) Strategic mitigation and opportunity actions per scenario, (6) Periodic update and review process.', fr: 'Évaluer : (1) Identification des risques émergents clés, (2) Construction de scénarios plausibles et différenciés, (3) Méthodologie rigoureuse, (4) Impact quantifié, (5) Actions stratégiques par scénario, (6) Processus de mise à jour périodique.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Emerging Risk Readiness (Scale)
  { id: 'ins-cro-rd-04', profileId: 'insurance-cro', categoryId: 'ins-cro-readiness', competencyId: 'ins-cro-emerging-risks', type: 'scale', content: { es: '¿Qué tan actualizado se mantiene sobre los riesgos emergentes que afectan a la industria aseguradora (riesgo climático, cibernético, pandémico, geopolítico, tecnológico) y su integración en los marcos de gestión de riesgos?', en: 'How up-to-date do you stay on emerging risks affecting the insurance industry (climate, cyber, pandemic, geopolitical, technological) and their integration into risk management frameworks?', fr: 'Dans quelle mesure êtes-vous à jour sur les risques émergents affectant l\'industrie de l\'assurance (climatique, cyber, pandémique, géopolitique, technologique) et leur intégration dans les cadres de gestion des risques ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento general sin aplicación práctica', en: 'General knowledge without practical application', fr: 'Connaissance générale sans application pratique' }, max: { es: 'Experto con experiencia implementando marcos de riesgos emergentes y contribuyendo a estándares del sector', en: 'Expert with experience implementing emerging risk frameworks and contributing to industry standards', fr: 'Expert avec expérience dans la mise en œuvre de cadres de risques émergents et contribution aux standards du secteur' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

// ============================================================================
// CUO (CHIEF UNDERWRITING OFFICER) QUESTIONS
// ============================================================================

export const insCuoProfessionalQuestions: Question[] = [
  // Underwriting Strategy
  { id: 'ins-cuo-pr-01', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-underwriting-strategy', type: 'scenario', content: { es: 'Su aseguradora multirramo tiene un ratio combinado del 102% en los últimos dos años, impulsado principalmente por las líneas de seguros de automóviles (108%) y responsabilidad civil (106%), mientras que propiedad comercial (94%) y vida grupo (91%) son rentables. El directorio exige un ratio combinado del 97% para el próximo año sin perder participación de mercado.\nContexto: Usted tiene el 12% del mercado en automóviles y es el tercer competidor. Los dos competidores principales están usando telemática y scoring avanzado. Su sistema de suscripción tiene 8 años de antigüedad. Los corredores representan el 65% de la distribución.', en: 'Your multi-line insurer has a 102% combined ratio over the past two years, driven mainly by auto insurance (108%) and liability lines (106%), while commercial property (94%) and group life (91%) are profitable. The board demands a 97% combined ratio next year without losing market share.\nContext: You have 12% market share in auto and are the third-largest competitor. The two leading competitors are using telematics and advanced scoring. Your underwriting system is 8 years old. Brokers represent 65% of distribution.', fr: 'Votre assureur multibranche a un ratio combiné de 102% depuis deux ans, principalement dû à l\'automobile (108%) et la responsabilité civile (106%). Le conseil exige un ratio combiné de 97% l\'an prochain sans perte de parts de marché.\nContexte : Vous avez 12% du marché auto. Les deux leaders utilisent la télématique et le scoring avancé. Votre système de souscription a 8 ans. Les courtiers représentent 65% de la distribution.' }, rubric: { es: 'Evaluar: (1) Diagnóstico diferenciado por ramo con análisis de granularidad (segmentos rentables vs. no rentables dentro de cada ramo), (2) Plan de acción específico para automóviles (segmentación, tarificación, selección de riesgo), (3) Estrategia de modernización de suscripción sin disrumpir la operación, (4) Gestión de la relación con corredores durante la transformación, (5) Balance entre disciplina de suscripción y objetivos comerciales, (6) Timeline realista con quick wins y metas progresivas.', en: 'Evaluate: (1) Differentiated diagnosis by line with granularity analysis, (2) Specific action plan for auto (segmentation, pricing, risk selection), (3) Underwriting modernization strategy without disrupting operations, (4) Broker relationship management during transformation, (5) Balance between underwriting discipline and commercial objectives, (6) Realistic timeline with quick wins and progressive goals.', fr: 'Évaluer : (1) Diagnostic différencié par branche avec analyse de granularité, (2) Plan d\'action spécifique pour l\'automobile, (3) Stratégie de modernisation de la souscription, (4) Gestion des courtiers pendant la transformation, (5) Équilibre discipline/objectifs commerciaux, (6) Timeline réaliste.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Portfolio Profitability
  { id: 'ins-cuo-pr-02', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-portfolio-profitability', type: 'multiple-choice', content: { es: 'El análisis de su cartera de seguros patrimoniales comerciales revela que el 20% de las pólizas generan el 65% de los siniestros. Sin embargo, estas pólizas representan cuentas corporativas importantes con múltiples líneas de negocio (patrimonial, responsabilidad civil, transportes). El ratio de siniestralidad de estas cuentas en patrimonial es 85%, pero en las otras líneas es inferior al 40%. ¿Cuál es su estrategia?', en: 'Analysis of your commercial property portfolio reveals that 20% of policies generate 65% of claims. However, these policies represent major corporate accounts with multiple business lines (property, liability, cargo). The claims ratio for these accounts in property is 85%, but in other lines it is below 40%. What is your strategy?', fr: 'L\'analyse de votre portefeuille d\'assurance de biens commerciaux révèle que 20% des polices génèrent 65% des sinistres. Cependant, ces polices représentent des comptes corporatifs importants avec de multiples branches. Le ratio de sinistralité en biens est de 85%, mais inférieur à 40% dans les autres branches. Quelle est votre stratégie ?' }, options: [{ id: 'a', text: { es: 'Realizar una revisión cuenta por cuenta: renegociar condiciones y deducibles en patrimonial, implementar requisitos de mejora de riesgo (inspecciones, protecciones), ajustar tarifas reflejando la experiencia real, y evaluar la rentabilidad integral multi-línea de cada cuenta antes de tomar decisiones de cancelación', en: 'Conduct an account-by-account review: renegotiate property terms and deductibles, implement risk improvement requirements (inspections, protections), adjust rates reflecting actual experience, and evaluate the comprehensive multi-line profitability of each account before making cancellation decisions', fr: 'Effectuer une révision compte par compte : renégocier les conditions et franchises en biens, exiger des améliorations de risque, ajuster les tarifs selon l\'expérience réelle, et évaluer la rentabilité multi-branches intégrale avant toute décision d\'annulation' }, value: 100 }, { id: 'b', text: { es: 'No renovar las pólizas de patrimonial de esas cuentas para mejorar inmediatamente el ratio de siniestralidad', en: 'Non-renew the property policies for those accounts to immediately improve the claims ratio', fr: 'Ne pas renouveler les polices de biens de ces comptes pour améliorer immédiatement le ratio de sinistralité' }, value: 10 }, { id: 'c', text: { es: 'Aumentar las tarifas de patrimonial un 30% de forma generalizada en toda la cartera comercial', en: 'Increase property rates by 30% across the entire commercial portfolio', fr: 'Augmenter les tarifs de biens de 30% sur tout le portefeuille commercial' }, value: 25 }, { id: 'd', text: { es: 'Comprar reaseguro adicional para cubrir la alta siniestralidad de esos riesgos', en: 'Purchase additional reinsurance to cover the high claims ratio on those risks', fr: 'Acheter de la réassurance supplémentaire pour couvrir la haute sinistralité de ces risques' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Pricing Adequacy
  { id: 'ins-cuo-pr-03', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-pricing-adequacy', type: 'scenario', content: { es: 'Su equipo actuarial presenta la revisión tarifaria anual de seguros de vehículos. Los resultados indican que se necesita un aumento promedio del 18% para lograr adecuación técnica. Sin embargo, la competencia acaba de reducir tarifas un 5% y su intermediario más importante (que aporta el 25% de la producción) amenaza con mover su cartera si hay aumentos superiores al 8%.\nContexto: La inflación en reparaciones automotrices fue del 22% el último año. La frecuencia de siniestros ha aumentado 8% post-pandemia. El regulador ha rechazado solicitudes de aumento superiores al 15% a otros competidores.', en: 'Your actuarial team presents the annual auto insurance rate review. Results indicate an average 18% increase is needed for technical adequacy. However, competition just reduced rates by 5% and your largest broker (25% of production) threatens to move their book if increases exceed 8%.\nContext: Auto repair inflation was 22% last year. Claims frequency has increased 8% post-pandemic. The regulator has rejected increase requests above 15% from other competitors.', fr: 'Votre équipe actuarielle présente la révision tarifaire annuelle automobile. Les résultats indiquent qu\'une augmentation moyenne de 18% est nécessaire. Cependant, la concurrence a réduit ses tarifs de 5% et votre plus grand courtier menace de déplacer son portefeuille si les augmentations dépassent 8%.\nContexte : L\'inflation des réparations a été de 22%. La fréquence des sinistres a augmenté de 8%. Le régulateur a rejeté des demandes d\'augmentation supérieures à 15%.' }, rubric: { es: 'Evaluar: (1) Estrategia de segmentación tarifaria diferenciada (no un aumento lineal), (2) Negociación con el intermediario basada en datos y valor de la relación, (3) Medidas complementarias al aumento tarifario (deducibles, condiciones, selección), (4) Gestión regulatoria proactiva con argumentación técnica, (5) Plan de retención para segmentos rentables, (6) Análisis de elasticidad precio-demanda por segmento.', en: 'Evaluate: (1) Differentiated rate segmentation strategy, (2) Broker negotiation based on data and relationship value, (3) Complementary measures beyond rate increases (deductibles, terms, selection), (4) Proactive regulatory management with technical argumentation, (5) Retention plan for profitable segments, (6) Price elasticity analysis by segment.', fr: 'Évaluer : (1) Stratégie de segmentation tarifaire différenciée, (2) Négociation avec le courtier, (3) Mesures complémentaires, (4) Gestion réglementaire proactive, (5) Plan de rétention des segments rentables, (6) Analyse d\'élasticité prix-demande.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Risk Selection
  { id: 'ins-cuo-pr-04', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-risk-selection', type: 'multiple-choice', content: { es: 'Un corredor importante le presenta una cuenta corporativa de una empresa minera con operaciones en zonas remotas. La prima potencial es USD 2.5M (sería la póliza más grande de su cartera de propiedad). Sin embargo, la inspección de riesgo revela: instalaciones de procesamiento sin sistema de supresión de incendios actualizado, historial de tres siniestros mayores en 5 años con otros aseguradores, y ubicación en zona de alta actividad sísmica sin refuerzos estructurales modernos. ¿Cómo procede?', en: 'A major broker presents a corporate account for a mining company with operations in remote areas. The potential premium is USD 2.5M (it would be the largest policy in your property portfolio). However, the risk inspection reveals: processing facilities without an updated fire suppression system, a history of three major claims in 5 years with other insurers, and location in a high seismic activity zone without modern structural reinforcements. How do you proceed?', fr: 'Un courtier important présente un compte corporatif d\'une entreprise minière en zone éloignée. La prime potentielle est de 2,5 M USD. L\'inspection de risque révèle : installations sans système d\'extinction d\'incendie, historique de trois sinistres majeurs en 5 ans, et localisation en zone sismique sans renforcements structurels modernes. Comment procédez-vous ?' }, options: [{ id: 'a', text: { es: 'Desarrollar una propuesta condicionada: aceptar el riesgo con una prima ajustada al riesgo real, deducibles elevados, cláusula de mejora de riesgo con calendario de implementación obligatorio (supresión de incendios en 6 meses, refuerzos sísmicos en 18 meses), sublímites para exposición sísmica, y programa de reaseguro facultativo específico', en: 'Develop a conditional proposal: accept the risk with a risk-adjusted premium, elevated deductibles, risk improvement clause with mandatory implementation timeline (fire suppression in 6 months, seismic reinforcements in 18 months), sublimits for seismic exposure, and specific facultative reinsurance program', fr: 'Développer une proposition conditionnée : accepter le risque avec une prime ajustée, des franchises élevées, une clause d\'amélioration du risque avec calendrier obligatoire, des sous-limites pour l\'exposition sismique, et un programme de réassurance facultative spécifique' }, value: 100 }, { id: 'b', text: { es: 'Rechazar el riesgo completamente dado el perfil de siniestralidad y las deficiencias de protección', en: 'Completely decline the risk given the claims profile and protection deficiencies', fr: 'Refuser complètement le risque vu le profil de sinistralité et les déficiences de protection' }, value: 35 }, { id: 'c', text: { es: 'Aceptar el riesgo tal como está para ganar la cuenta y al corredor', en: 'Accept the risk as-is to win the account and the broker', fr: 'Accepter le risque tel quel pour gagner le compte et le courtier' }, value: 10 }, { id: 'd', text: { es: 'Cotizar solo por la prima mínima aceptable técnicamente sin condiciones de mejora', en: 'Quote only for the minimum technically acceptable premium without improvement conditions', fr: 'Coter uniquement la prime minimum techniquement acceptable sans conditions d\'amélioration' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // Reinsurance Optimization
  { id: 'ins-cuo-pr-05', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-reinsurance-optimization', type: 'open-text', content: { es: 'El programa de reaseguro de su aseguradora vence en 90 días. Actualmente tiene una estructura de exceso de pérdida (XL) catastrófico de 3 capas, un contrato proporcional cuota parte del 30% en ramos patrimoniales, y facultativos individuales para riesgos grandes. Los costos de reaseguro han aumentado un 40% en dos años y su capacidad catastrófica se ha reducido. Como CUO, diseñe la estrategia de renovación del programa considerando que necesita mantener la protección adecuada a un costo eficiente.', en: 'Your insurer\'s reinsurance program expires in 90 days. It currently has a 3-layer catastrophe excess of loss (XL) structure, a 30% quota share proportional treaty on property lines, and individual facultative placements for large risks. Reinsurance costs have increased 40% over two years and your catastrophe capacity has decreased. As CUO, design the program renewal strategy considering you need to maintain adequate protection at an efficient cost.', fr: 'Le programme de réassurance de votre assureur expire dans 90 jours. Il comprend actuellement un XL catastrophe à 3 couches, un traité en quote-part de 30% en biens, et des facultatives individuelles. Les coûts ont augmenté de 40% en deux ans et la capacité catastrophe a diminué. En tant que CUO, concevez la stratégie de renouvellement du programme.' }, rubric: { es: 'Evaluar: (1) Análisis de la estructura actual vs. perfil de riesgo (eficiencia del costo de reaseguro por unidad de riesgo transferido), (2) Alternativas estructurales (aggregate XL, stop loss, ILS/cat bonds, sidecars), (3) Estrategia de negociación con reaseguradores (diversificación de panel, información de calidad, relaciones a largo plazo), (4) Optimización de la retención neta por ramo, (5) Análisis de la complementariedad entre proporcional y no proporcional, (6) Evaluación del uso de mecanismos alternativos de transferencia de riesgo.', en: 'Evaluate: (1) Analysis of current structure vs. risk profile, (2) Structural alternatives (aggregate XL, stop loss, ILS/cat bonds, sidecars), (3) Reinsurer negotiation strategy (panel diversification, quality information, long-term relationships), (4) Net retention optimization by line, (5) Proportional vs. non-proportional complementarity analysis, (6) Evaluation of alternative risk transfer mechanisms.', fr: 'Évaluer : (1) Analyse de la structure actuelle vs. profil de risque, (2) Alternatives structurelles (XL aggregate, stop loss, ILS/cat bonds), (3) Stratégie de négociation, (4) Optimisation de la rétention nette, (5) Complémentarité proportionnel/non-proportionnel, (6) Mécanismes alternatifs de transfert de risque.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Technical Reserving
  { id: 'ins-cuo-pr-06', profileId: 'insurance-cuo', categoryId: 'ins-cuo-professional', competencyId: 'ins-cuo-technical-reserving', type: 'scale', content: { es: '¿Qué nivel de conocimiento tiene sobre metodologías de reservas técnicas (Chain Ladder, Bornhuetter-Ferguson, Cape Cod) y su aplicación para evaluar la adecuación de reservas desde la perspectiva de suscripción?', en: 'What level of knowledge do you have regarding technical reserving methodologies (Chain Ladder, Bornhuetter-Ferguson, Cape Cod) and their application for evaluating reserve adequacy from an underwriting perspective?', fr: 'Quel niveau de connaissance avez-vous des méthodologies de réserves techniques (Chain Ladder, Bornhuetter-Ferguson, Cape Cod) et de leur application pour évaluer l\'adéquation des réserves du point de vue de la souscription ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Comprensión básica de los conceptos', en: 'Basic understanding of concepts', fr: 'Compréhension de base des concepts' }, max: { es: 'Dominio avanzado con capacidad de cuestionar y validar los resultados actuariales', en: 'Advanced mastery with ability to challenge and validate actuarial results', fr: 'Maîtrise avancée avec capacité de questionner et valider les résultats actuariels' } }, maxScore: 100, aiEvaluated: false, order: 6, isActive: true },
];

export const insCuoSoftSkillsQuestions: Question[] = [
  // Underwriter Development
  { id: 'ins-cuo-ss-01', profileId: 'insurance-cuo', categoryId: 'ins-cuo-soft-skills', competencyId: 'ins-cuo-underwriter-development', type: 'scenario', content: { es: 'Su equipo de suscripción (28 personas) tiene una distribución de experiencia polarizada: un grupo senior con más de 15 años que suscribe por "intuición" y resiste la adopción de herramientas analíticas, y un grupo junior altamente digital pero sin criterio técnico de suscripción. La rotación del grupo junior es del 30% anual porque son captados por insurtechs. Tres suscriptores senior se jubilarán en los próximos 18 meses.\nContexto: No existe un manual de suscripción formal actualizado. El conocimiento está en la cabeza de los suscriptores senior. La competencia está ofreciendo salarios 20% superiores a los suscriptores junior con habilidades analíticas.', en: 'Your underwriting team (28 people) has a polarized experience distribution: a senior group with 15+ years who underwrites by "intuition" and resists analytical tools, and a junior group that is highly digital but lacks underwriting technical judgment. Junior turnover is 30% annually as they are recruited by insurtechs. Three senior underwriters will retire within 18 months.\nContext: There is no formal updated underwriting manual. Knowledge resides with the senior underwriters. Competitors are offering 20% higher salaries to junior underwriters with analytical skills.', fr: 'Votre équipe de souscription (28 personnes) a une distribution d\'expérience polarisée : un groupe senior souscrivant par "intuition" et résistant aux outils analytiques, et un groupe junior très digital sans jugement technique. La rotation junior est de 30% par an. Trois seniors partent à la retraite dans 18 mois.\nContexte : Pas de manuel de souscription formel. Les connaissances sont détenues par les seniors. La concurrence offre des salaires 20% supérieurs aux juniors.' }, rubric: { es: 'Evaluar: (1) Plan de transferencia de conocimiento estructurado (mentorías, documentation, pair underwriting), (2) Estrategia de retención diferenciada para talento junior (carrera, compensación, propósito), (3) Programa de desarrollo de criterio de suscripción para juniors, (4) Gestión del cambio con suscriptores senior (respeto + evolución), (5) Creación de manual de suscripción codificando conocimiento tácito, (6) Métricas de éxito del programa de desarrollo.', en: 'Evaluate: (1) Structured knowledge transfer plan (mentoring, documentation, pair underwriting), (2) Differentiated retention strategy for junior talent, (3) Underwriting judgment development program for juniors, (4) Change management with senior underwriters, (5) Underwriting manual creation codifying tacit knowledge, (6) Development program success metrics.', fr: 'Évaluer : (1) Plan structuré de transfert de connaissances, (2) Stratégie de rétention différenciée pour les juniors, (3) Programme de développement du jugement de souscription, (4) Gestion du changement avec les seniors, (5) Création du manuel de souscription, (6) Métriques de succès.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Broker Relationships
  { id: 'ins-cuo-ss-02', profileId: 'insurance-cuo', categoryId: 'ins-cuo-soft-skills', competencyId: 'ins-cuo-broker-relationships', type: 'multiple-choice', content: { es: 'Su corredor más importante (30% de la producción) le presenta un ultimátum: exige comisiones superiores al mercado, condiciones de suscripción más flexibles y prioridad en el servicio de siniestros, amenazando con mover su cartera al competidor principal. Simultáneamente, usted sabe que la calidad técnica de los riesgos que coloca este corredor se ha deteriorado en los últimos dos años. ¿Cuál es su enfoque?', en: 'Your largest broker (30% of production) presents an ultimatum: demanding above-market commissions, more flexible underwriting terms, and priority claims service, threatening to move their book to your main competitor. Simultaneously, you know the technical quality of risks placed by this broker has deteriorated over the past two years. What is your approach?', fr: 'Votre plus grand courtier (30% de la production) vous lance un ultimatum : commissions supérieures au marché, conditions plus flexibles et priorité en sinistres, menaçant de déplacer son portefeuille. Parallèlement, la qualité technique des risques placés par ce courtier s\'est détériorée. Quelle est votre approche ?' }, options: [{ id: 'a', text: { es: 'Preparar una reunión estratégica con datos de rentabilidad detallados por segmento de su cartera: proponer un modelo de comisiones vinculadas a la calidad del riesgo (profit-sharing), ofrecer valor diferenciador en servicio y capacitación técnica a sus ejecutivos, y simultáneamente acelerar la diversificación de canales para reducir la dependencia', en: 'Prepare a strategic meeting with detailed profitability data by portfolio segment: propose a commission model linked to risk quality (profit-sharing), offer differentiating value in service and technical training for their staff, and simultaneously accelerate channel diversification to reduce dependency', fr: 'Préparer une réunion stratégique avec des données de rentabilité détaillées : proposer un modèle de commissions liées à la qualité du risque (participation aux bénéfices), offrir un service différenciant et une formation technique, et accélérer la diversification des canaux' }, value: 100 }, { id: 'b', text: { es: 'Ceder a todas las demandas del corredor para mantener la producción', en: 'Give in to all the broker\'s demands to maintain production', fr: 'Céder à toutes les demandes du courtier pour maintenir la production' }, value: 10 }, { id: 'c', text: { es: 'Rechazar todas las demandas y dejar que el corredor mueva la cartera', en: 'Reject all demands and let the broker move the book', fr: 'Rejeter toutes les demandes et laisser le courtier déplacer le portefeuille' }, value: 25 }, { id: 'd', text: { es: 'Escalar la negociación directamente al CEO para que intervenga', en: 'Escalate the negotiation directly to the CEO for intervention', fr: 'Escalader la négociation directement au PDG' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Executive Communication
  { id: 'ins-cuo-ss-03', profileId: 'insurance-cuo', categoryId: 'ins-cuo-soft-skills', competencyId: 'ins-cuo-executive-communication', type: 'open-text', content: { es: 'El directorio le solicita presentar la estrategia de suscripción para los próximos tres años. La audiencia incluye miembros del directorio sin experiencia en seguros, el CEO, el CFO y el CRO. Debe explicar conceptos técnicos complejos (adecuación tarifaria, selección de riesgo, ciclo de mercado, optimización del reaseguro) de manera accesible y lograr aprobación para inversiones significativas en tecnología de suscripción. Describa cómo estructuraría y presentaría esta propuesta.', en: 'The board asks you to present the underwriting strategy for the next three years. The audience includes board members without insurance experience, the CEO, CFO, and CRO. You must explain complex technical concepts (rate adequacy, risk selection, market cycle, reinsurance optimization) in an accessible way and gain approval for significant investments in underwriting technology. Describe how you would structure and present this proposal.', fr: 'Le conseil vous demande de présenter la stratégie de souscription pour les trois prochaines années. L\'audience inclut des membres sans expérience en assurance. Vous devez expliquer des concepts techniques complexes de manière accessible et obtenir l\'approbation d\'investissements technologiques significatifs. Décrivez comment vous structureriez et présenteriez cette proposition.' }, rubric: { es: 'Evaluar: (1) Estructura lógica de la presentación (diagnóstico, visión, plan, inversión, retorno), (2) Uso de analogías y visualizaciones para conceptos técnicos, (3) Conexión entre estrategia de suscripción y resultados financieros, (4) Business case convincente para la inversión en tecnología, (5) Anticipación de preguntas difíciles y preparación de respuestas, (6) Equilibrio entre ambición y realismo en las metas.', en: 'Evaluate: (1) Logical presentation structure (diagnosis, vision, plan, investment, return), (2) Use of analogies and visuals for technical concepts, (3) Connection between underwriting strategy and financial results, (4) Convincing business case for technology investment, (5) Anticipation of tough questions, (6) Balance between ambition and realism.', fr: 'Évaluer : (1) Structure logique de la présentation, (2) Utilisation d\'analogies et visualisations, (3) Connexion stratégie de souscription et résultats financiers, (4) Business case convaincant, (5) Anticipation des questions difficiles, (6) Équilibre ambition et réalisme.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Data Storytelling
  { id: 'ins-cuo-ss-04', profileId: 'insurance-cuo', categoryId: 'ins-cuo-soft-skills', competencyId: 'ins-cuo-data-storytelling', type: 'scale', content: { es: '¿Qué tan efectivo se considera transformando datos técnicos de suscripción (triángulos de siniestralidad, análisis de experiencia, modelos de tarificación) en narrativas comprensibles y persuasivas para audiencias no técnicas?', en: 'How effective do you consider yourself at transforming technical underwriting data (loss triangles, experience analysis, pricing models) into understandable and persuasive narratives for non-technical audiences?', fr: 'Dans quelle mesure vous considérez-vous efficace pour transformer des données techniques de souscription (triangles de sinistralité, analyses d\'expérience, modèles de tarification) en récits compréhensibles et persuasifs pour des audiences non-techniques ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me resulta difícil simplificar datos técnicos', en: 'I find it difficult to simplify technical data', fr: 'J\'ai du mal à simplifier les données techniques' }, max: { es: 'Domino el arte de contar historias con datos y logro influir en decisiones estratégicas', en: 'I master the art of data storytelling and consistently influence strategic decisions', fr: 'Je maîtrise l\'art du data storytelling et j\'influence régulièrement les décisions stratégiques' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

export const insCuoReadinessQuestions: Question[] = [
  // Predictive Underwriting / AI
  { id: 'ins-cuo-rd-01', profileId: 'insurance-cuo', categoryId: 'ins-cuo-readiness', competencyId: 'ins-cuo-predictive-underwriting', type: 'scenario', content: { es: 'Una firma de tecnología le propone implementar un motor de suscripción automatizada basado en inteligencia artificial que podría procesar el 70% de las solicitudes de seguros de PYMES sin intervención humana, reduciendo el tiempo de cotización de 3 días a 15 minutos. El modelo fue entrenado con datos de mercados desarrollados (EE.UU. y Europa) y tiene una precisión del 92% en esos mercados.\nContexto: Su mercado latinoamericano tiene características diferentes: menor calidad de datos públicos, informalidad empresarial, patrones de siniestralidad distintos. Su equipo de suscripción teme ser reemplazado. Los corredores exigen rapidez en las cotizaciones.', en: 'A technology firm proposes implementing an AI-based automated underwriting engine that could process 70% of SME insurance applications without human intervention, reducing quote time from 3 days to 15 minutes. The model was trained on developed market data (US and Europe) and has 92% accuracy in those markets.\nContext: Your Latin American market has different characteristics: lower quality public data, business informality, different claims patterns. Your underwriting team fears being replaced. Brokers demand faster quotes.', fr: 'Une firme technologique propose un moteur de souscription automatisée par IA capable de traiter 70% des demandes PME sans intervention humaine, réduisant le délai de cotation de 3 jours à 15 minutes. Le modèle a été entraîné sur des données de marchés développés avec 92% de précision.\nContexte : Votre marché latino-américain a des caractéristiques différentes : données de moindre qualité, informalité, patterns de sinistralité différents. Votre équipe craint d\'être remplacée.' }, rubric: { es: 'Evaluar: (1) Análisis crítico de la transferibilidad del modelo a mercados latinoamericanos, (2) Propuesta de calibración y validación local del modelo, (3) Diseño del modelo operativo humano-máquina (qué se automatiza vs. qué requiere juicio humano), (4) Plan de gestión del cambio con el equipo de suscripción, (5) Estrategia de implementación gradual con métricas de monitoreo, (6) Consideraciones éticas y regulatorias del uso de IA en suscripción.', en: 'Evaluate: (1) Critical analysis of model transferability to Latin American markets, (2) Local model calibration and validation proposal, (3) Human-machine operating model design, (4) Change management plan with underwriting team, (5) Gradual implementation strategy with monitoring metrics, (6) Ethical and regulatory considerations of AI in underwriting.', fr: 'Évaluer : (1) Analyse critique de la transférabilité du modèle, (2) Calibration et validation locale, (3) Modèle opérationnel humain-machine, (4) Gestion du changement, (5) Stratégie d\'implémentation graduelle, (6) Considérations éthiques et réglementaires.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Parametric Insurance
  { id: 'ins-cuo-rd-02', profileId: 'insurance-cuo', categoryId: 'ins-cuo-readiness', competencyId: 'ins-cuo-parametric-insurance', type: 'multiple-choice', content: { es: 'Su equipo comercial identifica una oportunidad de desarrollar seguros paramétricos para el sector agrícola en Centroamérica, utilizando índices de precipitación satelital como trigger de pago. El mercado potencial es significativo pero no existe experiencia previa en la empresa con productos paramétricos. ¿Cuál es su enfoque como CUO?', en: 'Your commercial team identifies an opportunity to develop parametric insurance for the agricultural sector in Central America, using satellite precipitation indices as payment triggers. The potential market is significant but the company has no prior experience with parametric products. What is your approach as CUO?', fr: 'Votre équipe commerciale identifie une opportunité de développer des assurances paramétriques pour l\'agriculture en Amérique centrale, utilisant des indices de précipitation satellite comme déclencheurs de paiement. Le marché potentiel est significatif mais l\'entreprise n\'a aucune expérience en produits paramétriques. Quelle est votre approche en tant que CUO ?' }, options: [{ id: 'a', text: { es: 'Diseñar un piloto controlado: seleccionar una región y un cultivo específico, asociarse con un proveedor de datos satelitales validado, desarrollar el producto con apoyo de reaseguradores especializados en paramétricos, definir el índice y umbral con datos históricos de al menos 20 años, y establecer métricas de riesgo base (basis risk) aceptables', en: 'Design a controlled pilot: select a specific region and crop, partner with a validated satellite data provider, develop the product with support from parametric-specialist reinsurers, define the index and threshold with at least 20 years of historical data, and establish acceptable basis risk metrics', fr: 'Concevoir un pilote contrôlé : sélectionner une région et une culture spécifiques, s\'associer avec un fournisseur de données satellite validé, développer le produit avec des réassureurs spécialisés en paramétrique, définir l\'indice et le seuil avec 20 ans de données historiques, et établir des métriques de risque de base acceptables' }, value: 100 }, { id: 'b', text: { es: 'Rechazar la oportunidad por falta de experiencia interna y riesgo de modelo desconocido', en: 'Reject the opportunity due to lack of internal experience and unknown model risk', fr: 'Rejeter l\'opportunité par manque d\'expérience interne et risque de modèle inconnu' }, value: 25 }, { id: 'c', text: { es: 'Lanzar el producto a gran escala rápidamente para capturar la ventaja de primer movimiento', en: 'Launch the product at full scale quickly to capture first-mover advantage', fr: 'Lancer le produit à grande échelle rapidement pour capturer l\'avantage du premier entrant' }, value: 10 }, { id: 'd', text: { es: 'Esperar a que un competidor lance primero y luego copiar su producto', en: 'Wait for a competitor to launch first and then copy their product', fr: 'Attendre qu\'un concurrent lance en premier puis copier son produit' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Climate-Adjusted Underwriting
  { id: 'ins-cuo-rd-03', profileId: 'insurance-cuo', categoryId: 'ins-cuo-readiness', competencyId: 'ins-cuo-climate-underwriting', type: 'open-text', content: { es: 'El cambio climático está alterando los patrones de riesgo de su cartera de seguros patrimoniales: aumento en la frecuencia e intensidad de huracanes en el Caribe, inundaciones más severas en zonas urbanas, y sequías prolongadas que afectan al sector agrícola. Los modelos catastróficos tradicionales basados en datos históricos están quedando obsoletos. Como CUO, describa cómo adaptaría su estrategia de suscripción para incorporar el riesgo climático de manera estructural.', en: 'Climate change is altering risk patterns in your property insurance portfolio: increased frequency and intensity of Caribbean hurricanes, more severe urban flooding, and prolonged droughts affecting the agricultural sector. Traditional catastrophe models based on historical data are becoming obsolete. As CUO, describe how you would adapt your underwriting strategy to structurally incorporate climate risk.', fr: 'Le changement climatique altère les patterns de risque de votre portefeuille d\'assurance de biens : augmentation de la fréquence des ouragans dans les Caraïbes, inondations urbaines plus sévères, et sécheresses prolongées affectant l\'agriculture. Les modèles catastrophiques traditionnels basés sur l\'historique deviennent obsolètes. En tant que CUO, décrivez comment vous adapteriez votre stratégie de souscription pour intégrer structurellement le risque climatique.' }, rubric: { es: 'Evaluar: (1) Integración de proyecciones climáticas (RCP scenarios) en los modelos de tarificación, (2) Revisión de los criterios de suscripción por zona geográfica con mapas de riesgo climático, (3) Desarrollo de productos adaptados (seguros paramétricos, coberturas de resiliencia), (4) Estrategia de gestión de acumulación de riesgo climático, (5) Colaboración con el CRO para alinear suscripción con apetito de riesgo climático, (6) Comunicación y educación del mercado sobre adaptación climática.', en: 'Evaluate: (1) Integration of climate projections (RCP scenarios) into pricing models, (2) Underwriting criteria revision by geographic zone with climate risk maps, (3) Development of adapted products (parametric insurance, resilience coverages), (4) Climate risk accumulation management strategy, (5) CRO collaboration to align underwriting with climate risk appetite, (6) Market communication and education on climate adaptation.', fr: 'Évaluer : (1) Intégration des projections climatiques dans la tarification, (2) Révision des critères de souscription par zone géographique, (3) Développement de produits adaptés, (4) Gestion de l\'accumulation de risque climatique, (5) Collaboration avec le CRO, (6) Communication et éducation du marché.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Readiness Scale
  { id: 'ins-cuo-rd-04', profileId: 'insurance-cuo', categoryId: 'ins-cuo-readiness', competencyId: 'ins-cuo-predictive-underwriting', type: 'scale', content: { es: '¿Qué tan familiarizado está con las nuevas tecnologías y tendencias que están transformando la suscripción de seguros (inteligencia artificial, IoT/telemática, seguros paramétricos, open insurance, suscripción straight-through)?', en: 'How familiar are you with new technologies and trends transforming insurance underwriting (artificial intelligence, IoT/telematics, parametric insurance, open insurance, straight-through underwriting)?', fr: 'Dans quelle mesure êtes-vous familiarisé avec les nouvelles technologies et tendances transformant la souscription d\'assurance (IA, IoT/télématique, assurance paramétrique, open insurance, souscription automatisée) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento superficial de estas tendencias', en: 'Surface-level knowledge of these trends', fr: 'Connaissance superficielle de ces tendances' }, max: { es: 'Experiencia práctica implementando varias de estas tecnologías en operaciones de suscripción', en: 'Practical experience implementing several of these technologies in underwriting operations', fr: 'Expérience pratique dans l\'implémentation de plusieurs de ces technologies en souscription' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

