export const insActuaryProfessionalQuestions: Question[] = [
  // Pricing / Tarification
  { id: 'ins-act-pr-01', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-pricing', type: 'scenario', content: { es: 'Su aseguradora planea lanzar un producto de seguro de salud individual en un mercado latinoamericano donde históricamente solo se han vendido pólizas colectivas. La base de datos disponible contiene solo tres años de experiencia de siniestralidad del seguro colectivo. El regulador exige una nota técnica con fundamentación actuarial detallada. La competencia tiene un producto similar con primas que usted sospecha están por debajo del costo técnico.\nContexto: La población objetivo tiene alta prevalencia de enfermedades crónicas no transmisibles. No existen tablas de morbilidad actualizadas para el mercado local. El regulador tiene antecedentes de rechazar notas técnicas insuficientes.', en: 'Your insurer plans to launch an individual health insurance product in a Latin American market where historically only group policies have been sold. The available database contains only three years of claims experience from group insurance. The regulator requires a technical note with detailed actuarial justification. Competition has a similar product with premiums you suspect are below technical cost.\nContext: The target population has high prevalence of chronic non-communicable diseases. No updated morbidity tables exist for the local market. The regulator has a history of rejecting insufficient technical notes.', fr: 'Votre assureur prévoit de lancer un produit d\'assurance santé individuelle dans un marché où seules les polices collectives ont été vendues. La base de données ne contient que trois ans d\'expérience. Le régulateur exige une note technique détaillée. La concurrence a des primes que vous soupçonnez être sous le coût technique.\nContexte : Haute prévalence de maladies chroniques. Pas de tables de morbidité actualisées pour le marché local.' }, rubric: { es: 'Evaluar: (1) Metodología de tarificación con datos limitados (credibilidad, complementación con tablas internacionales ajustadas), (2) Ajustes por antiselección en paso de colectivo a individual, (3) Modelación de riesgos crónicos y envejecimiento de cartera, (4) Estructura de prima (prima de riesgo, márgenes, gastos, beneficio), (5) Estrategia de precios sostenible vs. competencia (no seguir al mercado en precios inadecuados), (6) Documentación actuarial robusta para el regulador.', en: 'Evaluate: (1) Pricing methodology with limited data (credibility, supplementing with adjusted international tables), (2) Anti-selection adjustments from group to individual, (3) Chronic risk and portfolio aging modeling, (4) Premium structure (risk premium, margins, expenses, profit), (5) Sustainable pricing strategy vs. competition, (6) Robust actuarial documentation for the regulator.', fr: 'Évaluer : (1) Méthodologie de tarification avec données limitées, (2) Ajustements pour l\'antisélection, (3) Modélisation des risques chroniques, (4) Structure de la prime, (5) Stratégie de prix durable, (6) Documentation actuarielle robuste.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Reserving
  { id: 'ins-act-pr-02', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-reserving', type: 'multiple-choice', content: { es: 'La auditoría externa cuestiona la adecuación de las reservas de siniestros IBNR (Incurred But Not Reported) en la línea de responsabilidad civil profesional. Los triángulos de desarrollo muestran colas largas con volatilidad significativa. El método Chain Ladder produce una estimación 30% superior al método Bornhuetter-Ferguson. La diferencia representa USD 25 millones. ¿Cuál es su enfoque actuarial?', en: 'The external audit questions the adequacy of IBNR (Incurred But Not Reported) claims reserves in the professional liability line. Development triangles show long tails with significant volatility. The Chain Ladder method produces an estimate 30% higher than the Bornhuetter-Ferguson method. The difference represents USD 25 million. What is your actuarial approach?', fr: 'L\'audit externe questionne l\'adéquation des réserves IBNR en responsabilité civile professionnelle. Les triangles de développement montrent des queues longues avec une volatilité significative. Le Chain Ladder produit une estimation 30% supérieure au Bornhuetter-Ferguson. La différence représente 25 millions USD. Quelle est votre approche actuarielle ?' }, options: [{ id: 'a', text: { es: 'Aplicar múltiples métodos (Chain Ladder, BF, Cape Cod, modelos estocásticos de Mack) y analizar las causas de la divergencia: evaluar la estabilidad de los factores de desarrollo, revisar si hay cambios en el patrón de reportes, realizar análisis de sensibilidad, y seleccionar la estimación best estimate con documentación del rango de razonabilidad y margen de incertidumbre', en: 'Apply multiple methods (Chain Ladder, BF, Cape Cod, Mack stochastic models) and analyze the causes of divergence: evaluate development factor stability, review if there are reporting pattern changes, perform sensitivity analysis, and select the best estimate with documentation of the reasonableness range and uncertainty margin', fr: 'Appliquer de multiples méthodes (Chain Ladder, BF, Cape Cod, modèles stochastiques de Mack) et analyser les causes de la divergence : évaluer la stabilité des facteurs de développement, vérifier les changements de patterns de déclaration, effectuer une analyse de sensibilité, et sélectionner la meilleure estimation avec documentation du rang de raisonnabilité' }, value: 100 }, { id: 'b', text: { es: 'Utilizar el promedio simple de ambos métodos como estimación central', en: 'Use the simple average of both methods as the central estimate', fr: 'Utiliser la moyenne simple des deux méthodes comme estimation centrale' }, value: 35 }, { id: 'c', text: { es: 'Adoptar la estimación más conservadora (Chain Ladder) para evitar cuestionamientos de la auditoría', en: 'Adopt the more conservative estimate (Chain Ladder) to avoid audit challenges', fr: 'Adopter l\'estimation la plus conservatrice (Chain Ladder) pour éviter les questionnements de l\'audit' }, value: 25 }, { id: 'd', text: { es: 'Solicitar al equipo de siniestros una revisión caso por caso de los siniestros abiertos como base de la reserva', en: 'Request the claims team to do a case-by-case review of open claims as the basis for the reserve', fr: 'Demander à l\'équipe sinistres une révision au cas par cas des sinistres ouverts comme base de la réserve' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Capital Modeling (Solvency II / ORSA)
  { id: 'ins-act-pr-03', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-capital-modeling', type: 'scenario', content: { es: 'Su regulador ha implementado un nuevo marco de capital basado en riesgos (RBC) inspirado en Solvencia II. Su aseguradora debe realizar por primera vez un ORSA (Own Risk and Solvency Assessment) que incluya: cuantificación del capital económico, proyección de solvencia a 3 años bajo escenarios de estrés, y un informe al directorio sobre la adecuación del capital. El equipo actuarial tiene experiencia en modelos determinísticos pero no en modelos estocásticos de capital.\nContexto: El directorio cuestiona por qué el capital económico puede diferir significativamente del capital regulatorio. El CFO presiona por minimizar el capital inmovilizado. Plazo de entrega del primer ORSA: 6 meses.', en: 'Your regulator has implemented a new Risk-Based Capital (RBC) framework inspired by Solvency II. Your insurer must perform its first ORSA (Own Risk and Solvency Assessment) including: economic capital quantification, 3-year solvency projection under stress scenarios, and a board report on capital adequacy. The actuarial team has experience with deterministic models but not stochastic capital models.\nContext: The board questions why economic capital may differ significantly from regulatory capital. The CFO pushes to minimize tied-up capital. First ORSA deadline: 6 months.', fr: 'Votre régulateur a implémenté un nouveau cadre de capital basé sur les risques (RBC) inspiré de Solvabilité II. Votre assureur doit réaliser son premier ORSA incluant : quantification du capital économique, projection de solvabilité à 3 ans sous stress, et rapport au conseil.\nContexte : Le conseil questionne la différence entre capital économique et réglementaire. Le CFO pousse à minimiser le capital immobilisé. Délai : 6 mois.' }, rubric: { es: 'Evaluar: (1) Plan de proyecto del ORSA con gobernanza y responsabilidades claras, (2) Metodología de cuantificación del capital económico (modelo interno parcial o fórmula estándar calibrada), (3) Diseño de escenarios de estrés relevantes para el perfil de riesgo, (4) Explicación clara de la diferencia entre capital económico y regulatorio, (5) Estrategia de desarrollo de capacidades del equipo actuarial, (6) Formato y contenido del informe ORSA para el directorio.', en: 'Evaluate: (1) ORSA project plan with clear governance and responsibilities, (2) Economic capital quantification methodology (partial internal model or calibrated standard formula), (3) Design of relevant stress scenarios for the risk profile, (4) Clear explanation of the difference between economic and regulatory capital, (5) Actuarial team capability development strategy, (6) ORSA report format and content for the board.', fr: 'Évaluer : (1) Plan de projet ORSA avec gouvernance, (2) Méthodologie de quantification du capital économique, (3) Conception de scénarios de stress, (4) Explication de la différence capital économique vs. réglementaire, (5) Développement des capacités de l\'équipe, (6) Format du rapport ORSA.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Reinsurance Optimization (Actuarial Perspective)
  { id: 'ins-act-pr-04', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-reinsurance-optimization', type: 'multiple-choice', content: { es: 'El CUO le solicita evaluar actuarialmente dos alternativas para el programa de reaseguro catastrófico: Alternativa A — XL catastrófico tradicional con 3 capas que cubre hasta el PML 1/250 años a un costo de USD 12M. Alternativa B — Combinación de un XL de 2 capas hasta el PML 1/100 años (costo USD 7M) más un cat bond de USD 50M para la capa superior (costo USD 4M, 3 años). ¿Cuál es su análisis actuarial?', en: 'The CUO asks you to actuarially evaluate two alternatives for the catastrophe reinsurance program: Alternative A — Traditional 3-layer catastrophe XL covering up to the 1/250-year PML at a cost of USD 12M. Alternative B — Combination of a 2-layer XL up to the 1/100-year PML (cost USD 7M) plus a USD 50M cat bond for the upper layer (cost USD 4M, 3 years). What is your actuarial analysis?', fr: 'Le CUO vous demande d\'évaluer actuariellement deux alternatives pour le programme de réassurance catastrophe : Alternative A — XL catastrophe traditionnel à 3 couches couvrant jusqu\'au PML 1/250 ans (coût 12 M USD). Alternative B — Combinaison d\'un XL 2 couches jusqu\'au PML 1/100 ans (7 M USD) plus un cat bond de 50 M USD pour la couche supérieure (4 M USD, 3 ans). Quelle est votre analyse actuarielle ?' }, options: [{ id: 'a', text: { es: 'Realizar un análisis comparativo integral: modelar el ROL (Rate On Line) y la pérdida esperada de cada capa, calcular el costo del reaseguro por unidad de riesgo transferido, evaluar el riesgo de contraparte (reasegurador vs. SPV del cat bond), analizar la eficiencia de capital bajo el nuevo marco RBC, y considerar la diversificación de fuentes de capacidad y la estabilidad multi-anual del cat bond', en: 'Conduct a comprehensive comparative analysis: model the ROL (Rate On Line) and expected loss for each layer, calculate reinsurance cost per unit of transferred risk, evaluate counterparty risk (reinsurer vs. cat bond SPV), analyze capital efficiency under the new RBC framework, and consider capacity source diversification and the multi-year stability of the cat bond', fr: 'Réaliser une analyse comparative intégrale : modéliser le ROL et la perte attendue de chaque couche, calculer le coût de réassurance par unité de risque transféré, évaluer le risque de contrepartie, analyser l\'efficience de capital sous le cadre RBC, et considérer la diversification des sources de capacité et la stabilité multi-annuelle du cat bond' }, value: 100 }, { id: 'b', text: { es: 'Recomendar la Alternativa A porque es la estructura tradicional más comprendida por el mercado y el regulador', en: 'Recommend Alternative A because it is the traditional structure better understood by the market and regulator', fr: 'Recommander l\'Alternative A car c\'est la structure traditionnelle mieux comprise par le marché et le régulateur' }, value: 25 }, { id: 'c', text: { es: 'Recomendar la Alternativa B exclusivamente por ser más barata (USD 11M vs. USD 12M)', en: 'Recommend Alternative B exclusively because it is cheaper (USD 11M vs. USD 12M)', fr: 'Recommander l\'Alternative B exclusivement car elle est moins chère (11 M vs. 12 M USD)' }, value: 35 }, { id: 'd', text: { es: 'Delegar el análisis al equipo de reaseguro porque no es una función actuarial', en: 'Delegate the analysis to the reinsurance team because it is not an actuarial function', fr: 'Déléguer l\'analyse à l\'équipe de réassurance car ce n\'est pas une fonction actuarielle' }, value: 10 }], maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  // IFRS 17
  { id: 'ins-act-pr-05', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-ifrs17', type: 'open-text', content: { es: 'Su aseguradora debe implementar NIIF 17 (IFRS 17) y usted como Actuario Jefe es responsable de definir las metodologías actuariales clave. Describa las decisiones metodológicas principales que debe tomar, incluyendo: la elección entre modelo general (BBA) y modelo de asignación de primas (PAA) para cada línea de negocio, la determinación de la tasa de descuento, los ajustes por riesgo, los límites del contrato, y el tratamiento del CSM (Contractual Service Margin). Explique cómo estas decisiones impactan los estados financieros.', en: 'Your insurer must implement IFRS 17 and you as Chief Actuary are responsible for defining key actuarial methodologies. Describe the main methodological decisions you must make, including: the choice between the General Model (BBA) and Premium Allocation Approach (PAA) for each business line, discount rate determination, risk adjustments, contract boundaries, and CSM (Contractual Service Margin) treatment. Explain how these decisions impact financial statements.', fr: 'Votre assureur doit implémenter IFRS 17 et vous êtes responsable des méthodologies actuarielles clés. Décrivez les décisions méthodologiques principales : choix entre modèle général (BBA) et PAA par branche, détermination du taux d\'actualisation, ajustements pour risque, limites du contrat, et traitement du CSM. Expliquez l\'impact sur les états financiers.' }, rubric: { es: 'Evaluar: (1) Criterios de elegibilidad para PAA vs. BBA por ramo con análisis fundamentado, (2) Metodología de tasa de descuento (bottom-up vs. top-down, curvas de referencia), (3) Cuantificación del ajuste por riesgo (VaR, CTE, cost of capital), (4) Definición de límites del contrato con implicaciones en reconocimiento de ingresos, (5) Tratamiento del CSM y su amortización, (6) Comprensión del impacto en P&L, balance y ratios financieros.', en: 'Evaluate: (1) PAA vs. BBA eligibility criteria by line with reasoned analysis, (2) Discount rate methodology (bottom-up vs. top-down, reference curves), (3) Risk adjustment quantification (VaR, CTE, cost of capital), (4) Contract boundary definition with revenue recognition implications, (5) CSM treatment and amortization, (6) Understanding of impact on P&L, balance sheet, and financial ratios.', fr: 'Évaluer : (1) Critères d\'éligibilité PAA vs. BBA par branche, (2) Méthodologie du taux d\'actualisation, (3) Quantification de l\'ajustement pour risque, (4) Définition des limites du contrat, (5) Traitement du CSM et amortissement, (6) Compréhension de l\'impact sur les états financiers.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  // Experience Studies
  { id: 'ins-act-pr-06', profileId: 'insurance-actuary', categoryId: 'ins-actuary-professional', competencyId: 'ins-actuary-experience-studies', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene realizando estudios de experiencia actuarial (mortalidad, morbilidad, persistencia, frecuencia y severidad de siniestros) y utilizando los resultados para calibrar supuestos actuariales en modelos de pricing y reservas?', en: 'What level of experience do you have conducting actuarial experience studies (mortality, morbidity, persistency, claims frequency and severity) and using the results to calibrate actuarial assumptions in pricing and reserving models?', fr: 'Quel niveau d\'expérience avez-vous dans la réalisation d\'études d\'expérience actuarielle (mortalité, morbidité, persistance, fréquence et sévérité des sinistres) et l\'utilisation des résultats pour calibrer les hypothèses actuarielles dans les modèles de tarification et de réserves ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia básica con estudios simples de experiencia', en: 'Basic experience with simple experience studies', fr: 'Expérience de base avec des études d\'expérience simples' }, max: { es: 'Amplia experiencia liderando estudios de experiencia complejos multi-ramo con aplicación directa en modelos', en: 'Extensive experience leading complex multi-line experience studies with direct model application', fr: 'Vaste expérience dans la direction d\'études d\'expérience complexes multi-branches avec application directe dans les modèles' } }, maxScore: 100, aiEvaluated: false, order: 6, isActive: true },
];

export const insActuarySoftSkillsQuestions: Question[] = [
  // Translating Technical Findings
  { id: 'ins-act-ss-01', profileId: 'insurance-actuary', categoryId: 'ins-actuary-soft-skills', competencyId: 'ins-actuary-translating-findings', type: 'scenario', content: { es: 'Su modelo actuarial de capital económico muestra que la aseguradora tiene una probabilidad del 3.5% de insolvencia en un horizonte de 3 años si mantiene su estrategia actual de crecimiento agresivo en seguros de automóviles. El CEO, que no tiene formación actuarial, ha comprometido públicamente ante los accionistas un crecimiento del 25% anual en primas. Debe presentar estos hallazgos al CEO y al directorio de manera que comprendan la urgencia sin causar pánico ni ser percibido como obstruccionista.\nContexto: El CEO tiende a desestimar los análisis que percibe como excesivamente conservadores. Dos miembros del directorio son inversores activistas enfocados en crecimiento. El regulador ha aumentado su escrutinio sobre la adecuación de capital.', en: 'Your economic capital actuarial model shows the insurer has a 3.5% probability of insolvency over a 3-year horizon if it maintains its current aggressive auto insurance growth strategy. The CEO, who lacks actuarial background, has publicly committed to shareholders a 25% annual premium growth. You must present these findings to the CEO and board in a way they understand the urgency without causing panic or being perceived as obstructionist.\nContext: The CEO tends to dismiss analyses he perceives as overly conservative. Two board members are growth-focused activist investors. The regulator has increased capital adequacy scrutiny.', fr: 'Votre modèle de capital économique montre une probabilité d\'insolvabilité de 3,5% à 3 ans avec la stratégie de croissance actuelle en automobile. Le PDG a publiquement engagé une croissance de 25% par an. Vous devez présenter ces résultats de manière compréhensible et urgente, sans panique.\nContexte : Le PDG tend à rejeter les analyses trop conservatrices. Deux administrateurs sont des investisseurs activistes axés sur la croissance. Le régulateur renforce son contrôle.' }, rubric: { es: 'Evaluar: (1) Traducción de probabilidades técnicas a lenguaje de negocio comprensible, (2) Uso de escenarios y analogías para ilustrar el riesgo, (3) Presentación de alternativas estratégicas (no solo el problema), (4) Tono constructivo y orientado a soluciones, (5) Credibilidad técnica sin arrogancia, (6) Propuesta de crecimiento sostenible con métricas de capital.', en: 'Evaluate: (1) Translation of technical probabilities to understandable business language, (2) Use of scenarios and analogies to illustrate risk, (3) Presentation of strategic alternatives (not just the problem), (4) Constructive and solution-oriented tone, (5) Technical credibility without arrogance, (6) Sustainable growth proposal with capital metrics.', fr: 'Évaluer : (1) Traduction des probabilités techniques en langage commercial, (2) Utilisation de scénarios et analogies, (3) Présentation d\'alternatives stratégiques, (4) Ton constructif et orienté solutions, (5) Crédibilité technique sans arrogance, (6) Proposition de croissance durable avec métriques de capital.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Cross-Department Influence
  { id: 'ins-act-ss-02', profileId: 'insurance-actuary', categoryId: 'ins-actuary-soft-skills', competencyId: 'ins-actuary-cross-department', type: 'multiple-choice', content: { es: 'El equipo comercial ha diseñado un nuevo producto de seguro de vida con ahorro que ofrece una garantía de rendimiento mínimo del 5% anual. Su análisis actuarial muestra que esta garantía es insostenible en el entorno actual de tasas de interés y crea un riesgo significativo de ALM (Asset-Liability Management). El VP Comercial argumenta que sin esta garantía el producto no será competitivo y que ya se invirtió un presupuesto significativo en marketing. ¿Cómo maneja esta situación?', en: 'The commercial team has designed a new savings life insurance product offering a minimum guaranteed return of 5% per year. Your actuarial analysis shows this guarantee is unsustainable in the current interest rate environment and creates significant ALM (Asset-Liability Management) risk. The VP of Sales argues that without this guarantee the product will not be competitive and a significant marketing budget has already been invested. How do you handle this situation?', fr: 'L\'équipe commerciale a conçu un produit d\'assurance vie avec épargne garantissant un rendement minimum de 5% par an. Votre analyse actuarielle montre que cette garantie est insoutenable et crée un risque ALM significatif. Le VP Commercial argue que le produit ne sera pas compétitif sans cette garantie. Comment gérez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Presentar el análisis cuantitativo del riesgo de la garantía con escenarios de pérdida, y proponer alternativas técnicamente viables: garantía variable vinculada a un índice de referencia, participación en utilidades con un mínimo reducido (2-3%), o estructura de seguro universal con tasa variable y piso mínimo prudente, mostrando que pueden ser igualmente atractivas comercialmente', en: 'Present the quantitative risk analysis of the guarantee with loss scenarios, and propose technically viable alternatives: variable guarantee linked to a benchmark index, profit participation with a reduced minimum (2-3%), or universal life structure with variable rate and prudent minimum floor, showing they can be equally commercially attractive', fr: 'Présenter l\'analyse quantitative du risque de la garantie avec des scénarios de perte, et proposer des alternatives viables : garantie variable liée à un indice de référence, participation aux bénéfices avec minimum réduit (2-3%), ou structure en unités de compte avec plancher prudent' }, value: 100 }, { id: 'b', text: { es: 'Vetar el producto y emitir una opinión actuarial negativa formal', en: 'Veto the product and issue a formal negative actuarial opinion', fr: 'Opposer son veto au produit et émettre un avis actuariel négatif formel' }, value: 35 }, { id: 'c', text: { es: 'Aprobar la garantía del 5% para no obstaculizar la estrategia comercial', en: 'Approve the 5% guarantee to not obstruct the commercial strategy', fr: 'Approuver la garantie de 5% pour ne pas entraver la stratégie commerciale' }, value: 10 }, { id: 'd', text: { es: 'Escalar directamente al regulador para que prohíba este tipo de garantías en el mercado', en: 'Escalate directly to the regulator to have them prohibit this type of guarantee in the market', fr: 'Escalader directement au régulateur pour qu\'il interdise ce type de garanties' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Mentoring
  { id: 'ins-act-ss-03', profileId: 'insurance-actuary', categoryId: 'ins-actuary-soft-skills', competencyId: 'ins-actuary-mentoring', type: 'open-text', content: { es: 'El departamento actuarial de su aseguradora tiene 12 profesionales, pero solo 3 (incluyéndose) son actuarios certificados. La mayoría del equipo son matemáticos o estadísticos jóvenes con 2-4 años de experiencia que necesitan completar sus exámenes de certificación actuarial. La tasa de aprobación de exámenes ha sido baja (25%) y la rotación es alta porque los que se certifican son reclutados por la competencia o consultoras. Describa su estrategia integral para desarrollar y retener talento actuarial.', en: 'Your insurer\'s actuarial department has 12 professionals, but only 3 (including yourself) are certified actuaries. Most of the team are young mathematicians or statisticians with 2-4 years of experience who need to complete their actuarial certification exams. The exam pass rate has been low (25%) and turnover is high because those who certify are recruited by competitors or consultancies. Describe your comprehensive strategy for developing and retaining actuarial talent.', fr: 'Le département actuariel a 12 professionnels, mais seuls 3 (dont vous) sont des actuaires certifiés. La plupart sont de jeunes mathématiciens ou statisticiens avec 2-4 ans d\'expérience devant compléter leur certification. Le taux de réussite aux examens est de 25% et la rotation est élevée car les certifiés sont recrutés par la concurrence. Décrivez votre stratégie globale de développement et de rétention du talent actuariel.' }, rubric: { es: 'Evaluar: (1) Programa estructurado de preparación para exámenes (tiempo de estudio, materiales, tutorías), (2) Programa de mentoría con asignación de proyectos progresivos, (3) Estrategia de retención (compensación competitiva, plan de carrera, beneficios de certificación), (4) Creación de comunidad de práctica actuarial, (5) Rotación por áreas (pricing, reservas, capital, reaseguro) para desarrollo integral, (6) Vinculación con asociaciones actuariales locales e internacionales.', en: 'Evaluate: (1) Structured exam preparation program (study time, materials, tutoring), (2) Mentoring program with progressive project assignments, (3) Retention strategy (competitive compensation, career path, certification benefits), (4) Actuarial community of practice creation, (5) Area rotation (pricing, reserves, capital, reinsurance) for comprehensive development, (6) Connection with local and international actuarial associations.', fr: 'Évaluer : (1) Programme structuré de préparation aux examens, (2) Programme de mentorat avec projets progressifs, (3) Stratégie de rétention, (4) Communauté de pratique actuarielle, (5) Rotation entre domaines, (6) Liens avec les associations actuarielles.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Regulatory Relationships
  { id: 'ins-act-ss-04', profileId: 'insurance-actuary', categoryId: 'ins-actuary-soft-skills', competencyId: 'ins-actuary-regulatory-relationships', type: 'scale', content: { es: '¿Qué tan efectivo se considera construyendo relaciones profesionales con reguladores de seguros, participando en consultas regulatorias técnicas y representando la perspectiva actuarial de la empresa ante la autoridad supervisora?', en: 'How effective do you consider yourself at building professional relationships with insurance regulators, participating in technical regulatory consultations, and representing the company\'s actuarial perspective before the supervisory authority?', fr: 'Dans quelle mesure vous considérez-vous efficace pour construire des relations professionnelles avec les régulateurs d\'assurance, participer aux consultations réglementaires techniques et représenter la perspective actuarielle de l\'entreprise devant l\'autorité de supervision ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Interacción limitada con reguladores', en: 'Limited interaction with regulators', fr: 'Interaction limitée avec les régulateurs' }, max: { es: 'Relación establecida como interlocutor técnico de confianza con múltiples reguladores, con participación activa en la definición de estándares del sector', en: 'Established relationship as a trusted technical interlocutor with multiple regulators, with active participation in defining industry standards', fr: 'Relation établie comme interlocuteur technique de confiance avec de multiples régulateurs et participation active dans la définition des standards du secteur' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];

export const insActuaryReadinessQuestions: Question[] = [
  // ML in Actuarial Science
  { id: 'ins-act-rd-01', profileId: 'insurance-actuary', categoryId: 'ins-actuary-readiness', competencyId: 'ins-actuary-ml-actuarial', type: 'scenario', content: { es: 'Su equipo de data science propone reemplazar los modelos GLM (Generalized Linear Models) tradicionales de tarificación de automóviles con modelos de gradient boosting (XGBoost/LightGBM) que muestran un 15% de mejora en la predicción de siniestralidad en el backtesting. Sin embargo, el regulador exige que las notas técnicas contengan modelos "interpretables" y varios miembros de su equipo actuarial cuestionan la validez actuarial de los modelos de machine learning.\nContexto: La competencia ya está usando modelos ML con aprobación regulatoria en otros mercados. Su sistema de tarificación actual tiene 7 años de antigüedad. Los corredores se quejan de que sus tarifas no reflejan adecuadamente el riesgo individual.', en: 'Your data science team proposes replacing traditional GLM (Generalized Linear Models) for auto insurance pricing with gradient boosting models (XGBoost/LightGBM) showing a 15% improvement in claims prediction in backtesting. However, the regulator requires that technical notes contain "interpretable" models and several actuarial team members question the actuarial validity of machine learning models.\nContext: Competition is already using ML models with regulatory approval in other markets. Your current pricing system is 7 years old. Brokers complain that your rates do not adequately reflect individual risk.', fr: 'Votre équipe de data science propose de remplacer les modèles GLM traditionnels de tarification automobile par des modèles de gradient boosting (XGBoost/LightGBM) montrant 15% d\'amélioration dans la prédiction de sinistralité. Cependant, le régulateur exige des modèles "interprétables" dans les notes techniques.\nContexte : La concurrence utilise déjà des modèles ML avec approbation réglementaire dans d\'autres marchés. Votre système de tarification a 7 ans.' }, rubric: { es: 'Evaluar: (1) Propuesta de integración GLM + ML (modelos interpretables como base regulatoria, ML como capa de refinamiento), (2) Técnicas de explicabilidad aplicadas a modelos ML (SHAP values, PDP, feature importance), (3) Framework de validación actuarial para modelos ML (backtesting, out-of-sample, estabilidad temporal), (4) Estrategia regulatoria para obtener aprobación, (5) Plan de transición y gestión del cambio con el equipo actuarial, (6) Gobernanza de modelos (monitoreo, recalibración, documentación).', en: 'Evaluate: (1) GLM + ML integration proposal (interpretable models as regulatory base, ML as refinement layer), (2) Explainability techniques applied to ML models (SHAP values, PDP, feature importance), (3) Actuarial validation framework for ML models (backtesting, out-of-sample, temporal stability), (4) Regulatory strategy for obtaining approval, (5) Transition plan and change management with actuarial team, (6) Model governance (monitoring, recalibration, documentation).', fr: 'Évaluer : (1) Proposition d\'intégration GLM + ML, (2) Techniques d\'explicabilité des modèles ML, (3) Cadre de validation actuarielle pour les modèles ML, (4) Stratégie réglementaire, (5) Plan de transition et gestion du changement, (6) Gouvernance des modèles.' }, maxScore: 100, aiEvaluated: true, order: 1, isActive: true },
  // Climate Risk Modeling
  { id: 'ins-act-rd-02', profileId: 'insurance-actuary', categoryId: 'ins-actuary-readiness', competencyId: 'ins-actuary-climate-modeling', type: 'multiple-choice', content: { es: 'La junta directiva solicita que el departamento actuarial integre el riesgo de cambio climático en los modelos de tarificación y reservas de la aseguradora. Los modelos actuariales actuales se basan en 20 años de datos históricos que no reflejan las tendencias climáticas recientes. ¿Cuál es su enfoque como Actuario Jefe?', en: 'The board requests that the actuarial department integrate climate change risk into the insurer\'s pricing and reserving models. Current actuarial models are based on 20 years of historical data that do not reflect recent climate trends. What is your approach as Chief Actuary?', fr: 'Le conseil demande que le département actuariel intègre le risque de changement climatique dans les modèles de tarification et de réserves. Les modèles actuels se basent sur 20 ans de données historiques ne reflétant pas les tendances climatiques récentes. Quelle est votre approche en tant qu\'Actuaire en Chef ?' }, options: [{ id: 'a', text: { es: 'Desarrollar un marco actuarial integrado: incorporar datos de proyecciones climáticas (IPCC RCP/SSP) como variables exógenas en los modelos, aplicar factores de tendencia climática a las series históricas, implementar cargos prospectivos (forward-looking loadings) por riesgo climático en la tarificación, y realizar estudios de adecuación de reservas con escenarios climáticos a 10-20 años', en: 'Develop an integrated actuarial framework: incorporate climate projection data (IPCC RCP/SSP) as exogenous variables in models, apply climate trend factors to historical series, implement forward-looking climate risk loadings in pricing, and conduct reserve adequacy studies with 10-20 year climate scenarios', fr: 'Développer un cadre actuariel intégré : incorporer les projections climatiques (IPCC RCP/SSP) comme variables exogènes, appliquer des facteurs de tendance climatique aux séries historiques, implémenter des chargements prospectifs pour le risque climatique, et réaliser des études d\'adéquation des réserves avec des scénarios climatiques à 10-20 ans' }, value: 100 }, { id: 'b', text: { es: 'Agregar un margen de seguridad generalizado del 10-15% a todas las tarifas de ramos expuestos al clima', en: 'Add a generalized 10-15% safety margin to all rates for climate-exposed lines', fr: 'Ajouter une marge de sécurité généralisée de 10-15% à toutes les tarifs des branches exposées au climat' }, value: 35 }, { id: 'c', text: { es: 'Esperar a que se desarrollen estándares actuariales específicos para el riesgo climático antes de actuar', en: 'Wait for specific actuarial standards for climate risk to be developed before acting', fr: 'Attendre que des standards actuariels spécifiques au risque climatique soient développés avant d\'agir' }, value: 10 }, { id: 'd', text: { es: 'Contratar una consultora especializada en clima para que desarrolle los modelos', en: 'Hire a climate-specialized consultancy to develop the models', fr: 'Engager un cabinet spécialisé en climat pour développer les modèles' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  // Real-Time Pricing / Telematics
  { id: 'ins-act-rd-03', profileId: 'insurance-actuary', categoryId: 'ins-actuary-readiness', competencyId: 'ins-actuary-realtime-pricing', type: 'open-text', content: { es: 'La industria aseguradora está evolucionando hacia modelos de tarificación en tiempo real basados en datos de IoT y telemática: seguros de auto que ajustan la prima según el comportamiento de conducción, seguros de salud vinculados a wearables, y seguros de hogar conectados a sensores inteligentes. Como Actuario Jefe, describa cómo transformaría el paradigma actuarial tradicional (tarifas anuales basadas en clases de riesgo estáticas) hacia un modelo de tarificación dinámica, considerando los desafíos técnicos, regulatorios, éticos y operativos.', en: 'The insurance industry is evolving toward real-time pricing models based on IoT and telematics data: auto insurance that adjusts premiums based on driving behavior, health insurance linked to wearables, and home insurance connected to smart sensors. As Chief Actuary, describe how you would transform the traditional actuarial paradigm (annual rates based on static risk classes) toward a dynamic pricing model, considering the technical, regulatory, ethical, and operational challenges.', fr: 'L\'industrie évolue vers des modèles de tarification en temps réel basés sur l\'IoT et la télématique. En tant qu\'Actuaire en Chef, décrivez comment vous transformeriez le paradigme actuariel traditionnel (tarifs annuels basés sur des classes de risque statiques) vers un modèle de tarification dynamique, en considérant les défis techniques, réglementaires, éthiques et opérationnels.' }, rubric: { es: 'Evaluar: (1) Diseño del modelo actuarial de tarificación dinámica (cómo integrar datos de comportamiento en tiempo real con factores de riesgo tradicionales), (2) Infraestructura de datos y tecnología requerida, (3) Desafíos regulatorios (aprobación de tarifas variables, protección de datos, no discriminación), (4) Consideraciones éticas (privacidad, accesibilidad, equidad), (5) Impacto en reservas y rentabilidad (cómo reservar con primas variables), (6) Roadmap de implementación escalonada con piloto.', en: 'Evaluate: (1) Dynamic pricing actuarial model design (integrating real-time behavioral data with traditional risk factors), (2) Required data infrastructure and technology, (3) Regulatory challenges (variable rate approval, data protection, non-discrimination), (4) Ethical considerations (privacy, accessibility, fairness), (5) Impact on reserves and profitability (reserving with variable premiums), (6) Phased implementation roadmap with pilot.', fr: 'Évaluer : (1) Conception du modèle de tarification dynamique, (2) Infrastructure de données et technologie requises, (3) Défis réglementaires, (4) Considérations éthiques, (5) Impact sur les réserves et la rentabilité, (6) Feuille de route d\'implémentation échelonnée.' }, maxScore: 100, aiEvaluated: true, order: 3, isActive: true },
  // Readiness Scale
  { id: 'ins-act-rd-04', profileId: 'insurance-actuary', categoryId: 'ins-actuary-readiness', competencyId: 'ins-actuary-ml-actuarial', type: 'scale', content: { es: '¿Qué tan preparado está para integrar técnicas de ciencia de datos y machine learning (GLMs avanzados, gradient boosting, redes neuronales, NLP) en la práctica actuarial tradicional de su organización?', en: 'How prepared are you to integrate data science and machine learning techniques (advanced GLMs, gradient boosting, neural networks, NLP) into your organization\'s traditional actuarial practice?', fr: 'Dans quelle mesure êtes-vous préparé pour intégrer des techniques de data science et de machine learning (GLMs avancés, gradient boosting, réseaux neuronaux, NLP) dans la pratique actuarielle traditionnelle de votre organisation ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conocimiento teórico básico sin aplicación práctica', en: 'Basic theoretical knowledge without practical application', fr: 'Connaissance théorique de base sans application pratique' }, max: { es: 'He implementado exitosamente modelos ML en producción actuarial con gobernanza y validación', en: 'I have successfully implemented ML models in actuarial production with governance and validation', fr: 'J\'ai implémenté avec succès des modèles ML en production actuarielle avec gouvernance et validation' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
];
